-- =============================================================================
-- 20260603_010_azkar_screenshots_import
--
-- Imports azkar extracted from the 'Dua and Adhkar' reference app screenshots.
-- Touches ONLY these 6 categories (Morning/Evening are explicitly preserved):
--   duas_before_sleep, duas_after_salah, daily_duas,
--   remembrance_of_allah, rabbana_40, ruquiya
--
-- Adds two columns to azkar_items:
--   title                    TEXT - display name (e.g. 'When Sneezing')
--   recommended_count_label  TEXT - non-numeric counts (e.g. '33+33+34')
-- =============================================================================

BEGIN;

-- 1. Schema additions ------------------------------------------------------
ALTER TABLE azkar_items ADD COLUMN IF NOT EXISTS title TEXT;
ALTER TABLE azkar_items ADD COLUMN IF NOT EXISTS recommended_count_label TEXT;

-- 2. Upsert categories ----------------------------------------------------
INSERT INTO azkar_categories (id, label, icon_name, sort_order, is_visible) VALUES
  ('duas_before_sleep', 'Duas before Sleep', 'bedtime_rounded', 100, true),
  ('duas_after_salah', 'Duas after Salah', 'mosque_rounded', 110, true),
  ('daily_duas', 'Daily Duas', 'auto_awesome_rounded', 120, true),
  ('remembrance_of_allah', 'Remembrance of Allah', 'auto_awesome_rounded', 130, true),
  ('rabbana_40', '40 Rabbana Duas', 'bookmark_rounded', 140, true),
  ('ruquiya', 'Ruquiya', 'shield_rounded', 150, true)
ON CONFLICT (id) DO UPDATE SET
  label      = EXCLUDED.label,
  icon_name  = EXCLUDED.icon_name,
  sort_order = EXCLUDED.sort_order,
  is_visible = EXCLUDED.is_visible;

-- 3. Wipe existing rows in the 6 target categories ----------------------
-- (Morning/Evening intentionally excluded.)
DELETE FROM azkar_item_categories WHERE category_id IN ('duas_before_sleep', 'duas_after_salah', 'ruquiya', 'rabbana_40', 'remembrance_of_allah', 'daily_duas');
DELETE FROM azkar_items WHERE category_id IN ('duas_before_sleep', 'duas_after_salah', 'ruquiya', 'rabbana_40', 'remembrance_of_allah', 'daily_duas');

-- 4. Insert azkar items --------------------------------------------------
INSERT INTO azkar_items
  (id, title, arabic, transliteration, translation,
   recommended_count, recommended_count_label, category_id,
   reward, reference, sort_order, hadith_full)
VALUES
  ('sleep_before_001', 'Dhikr before Sleeping', 'سُبْحَانَ اللهِ (×33) اَلْحَمْدُ لِلهِ (×33) اَللهُ اَكْبَرُ (×34)', 'Subhan Allah (33), Alhamdulillah (33), Allahu Akbar (34)', 'Glorious is Allah (33). Praises are due to Allah (33). Allah is the greatest (34).', 100, '33+33+34', 'duas_before_sleep', 'Narrated `Ali bin Abi Talib (RA): Fatima came to the Prophet (ﷺ) asking for a servant. He said, "May I inform you of something better than that? When you go to bed, recite Subhan Allah thirty-three times, Al-hamdu li-lah thirty-three times, and Allahu Akbar thirty-four times."', 'Sahih al-Bukhari 5362', 1, 'Narrated `Ali bin Abi Talib (RA): Fatima came to the Prophet (ﷺ) asking for a servant. He said, "May I inform you of something better than that? When you go to bed, recite Subhan Allah thirty-three times, Al-hamdu li-lah thirty-three times, and Allahu Akbar thirty-four times."'),
  ('salah_after_002', 'After every Fard Salah', 'اَسْتَغْفِرُ اللهَ', 'Astaghfirullah', 'I ask Allah to forgive me.', 3, NULL, 'duas_after_salah', 'Thauban (RA) reported: When the Messenger of Allah (ﷺ) finished his prayer, he would seek forgiveness from Allah three times and he would say, "O Allah, You are peace and from You is peace, Blessed are You, Majestic and Generous."', 'Sahih Muslim 591 | Hisn al-Muslim 66', 2, 'Thauban (RA) reported: When the Messenger of Allah (ﷺ) finished his prayer, he would seek forgiveness from Allah three times and he would say, "O Allah, You are peace and from You is peace, Blessed are You, Majestic and Generous."'),
  ('salah_after_003', 'After every Fard Salah', 'اَللّٰهُمَّ اَنْتَ السَّلَامُ، وَمِنْكَ السَّلَامُ، تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْاِكْرَامِ', 'Allahumma antas-salaam, Wa minkas-salaam, Tabaarakta ya dhal-jalaali wal-ikram', 'O Allah! You are peace and from You comes peace. Blessed are You, O owner of Majesty and Honour.', 1, NULL, 'duas_after_salah', 'Thauban (RA) reported: When the Messenger of Allah (ﷺ) finished his prayer, he would seek forgiveness from Allah three times and he would say, "O Allah, You are peace and from You is peace, Blessed are You, Majestic and Generous." Aisha (RA) said: When the Prophet (ﷺ) uttered taslim, he used to say: "O Allah, You are As-Salam, and from you is As-Salam. You are blessed, O One of Magnificence and Generosity."', 'Sahih Muslim 591 | Sunan Abi Dawud 1512 | Hisn al-Muslim 66', 3, 'Thauban (RA) reported: When the Messenger of Allah (ﷺ) finished his prayer, he would seek forgiveness from Allah three times and he would say, "O Allah, You are peace and from You is peace, Blessed are You, Majestic and Generous." Aisha (RA) said: When the Prophet (ﷺ) uttered taslim, he used to say: "O Allah, You are As-Salam, and from you is As-Salam. You are blessed, O One of Magnificence and Generosity."'),
  ('salah_after_004', 'After every Fard Salah', 'اَللّٰهُمَّ اَعِنِّيْ عَلَىٰ ذِكْرِكَ، وَشُكْرِكَ، وَحُسْنِ عِبَادَتِكَ', 'Allahumma a''inni ala dhikrika, Wa shukrika, Wa husni ''ibaadatik', 'O Allah! Assist me in remembering you, in thanking you, and worshipping you in the best of manners.', 1, NULL, 'duas_after_salah', 'Mu''adh b. Jabal (RA) reported that the Messenger of Allah (ﷺ) caught his hand and said: By Allah, I love you, Mu''adh. I give some instruction to you. Never leave to recite this supplication after every (prescribed) prayer: "O Allah, help me in remembering You, in giving You thanks, and worshipping You well."', 'Sunan Abi Dawud 1522', 4, 'Mu''adh b. Jabal (RA) reported that the Messenger of Allah (ﷺ) caught his hand and said: By Allah, I love you, Mu''adh. I give some instruction to you. Never leave to recite this supplication after every (prescribed) prayer: "O Allah, help me in remembering You, in giving You thanks, and worshipping You well."'),
  ('salah_after_006', '33 times each followed by 1x', 'سُبْحَانَ اللهِ (×33) اَلْحَمْدُ لِلّٰهِ (×33) اَللّٰهُ اَكْبَرُ (×33) لَا اِلٰهَ اِلَّا اللّٰهُ وَحْدَهُ لَا شَرِيْكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، وَهُوَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ', 'Subhan Allah (x33), Alhamdulillah (x33), Allahu Akbar (x33). Followed by (x1): Laa ilaaha illallaah, Wahdahu laa shareeka lah, Lahul mulku wa lahul hamd, Wahuwa ''ala kulli shay''in qadeer', 'Glorious is Allah (x33). Praises are due to Allah (x33). Allah is the greatest (x33). Followed by (x1): None has the right to be worshipped except Allah, alone, without partner, to Him belongs all sovereignty and praise, and He is over all things omnipotent.', 100, '33+33+33+1', 'duas_after_salah', 'Abu Huraira (RA) reported Allah''s Messenger (ﷺ) as saying: If anyone extols Allah after every prayer thirty-three times, and praises Allah thirty-three times, and declares His Greatness thirty-three times, ninety-nine times in all, and says to complete a hundred: "There is no god but Allah, having no partner with Him, to Him belongs sovereignty and to Him is praise due, and He is Potent over everything," his sins will be forgiven even if these are as abundant as the foam of the sea.', 'Sahih Muslim 597a | Hisn al-Muslim 69', 6, 'Abu Huraira (RA) reported Allah''s Messenger (ﷺ) as saying: If anyone extols Allah after every prayer thirty-three times, and praises Allah thirty-three times, and declares His Greatness thirty-three times, ninety-nine times in all, and says to complete a hundred: "There is no god but Allah, having no partner with Him, to Him belongs sovereignty and to Him is praise due, and He is Potent over everything," his sins will be forgiven even if these are as abundant as the foam of the sea.'),
  ('salah_after_008', 'After Fajr only', 'اَللّٰهُمَّ اِنِّيْ اَسْاَلُكَ عِلْمًا نَافِعًا، وَرِزْقًا طَيِّبًا، وَعَمَلًا مُتَقَبَّلًا', 'Allahumma inni as''aluka ''ilman naafi''an, Wa rizqan tayyiban, Wa ''amalan mutaqabbalan', 'O Allah, I ask You for knowledge which is beneficial and sustenance which is good, and deeds which are acceptable.', 1, NULL, 'duas_after_salah', 'It was narrated from Umm Salamah (RA) that when the Prophet (ﷺ) performed the Subh (morning prayer), while he said the Salam, he would say: ''Allahumma inni as''aluka ''ilman nafi''an, wa rizqan tayyiban, wa ''amalan mutaqabbalan (O Allah, I ask You for beneficial knowledge, goodly provision and acceptable deeds).''', 'Sunan Ibn Majah 925 | Hisn al-Muslim 95', 8, 'It was narrated from Umm Salamah (RA) that when the Prophet (ﷺ) performed the Subh (morning prayer), while he said the Salam, he would say: ''Allahumma inni as''aluka ''ilman nafi''an, wa rizqan tayyiban, wa ''amalan mutaqabbalan (O Allah, I ask You for beneficial knowledge, goodly provision and acceptable deeds).'''),
  ('salah_after_009', 'After every Fard Salah', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. اَللّٰهُ لَآ اِلٰهَ اِلَّا هُوَ الْحَىُّ الْقَيُّوْمُ، لَا تَأْخُذُهُۥ سِنَةٌ وَّلَا نَوْمٌ، لَهُ مَا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِ، مَنْ ذَا الَّذِىْ يَشْفَعُ عِنْدَهُۥ اِلَّا بِاِذْنِهِۦ، يَعْلَمُ مَا بَيْنَ اَيْدِيْهِمْ وَمَا خَلْفَهُمْ، وَلَا يُحِيْطُوْنَ بِشَىْءٍ مِّنْ عِلْمِهِۦۤ اِلَّا بِمَا شَآءَ، وَسِعَ كُرْسِيُّهُ السَّمٰوٰتِ وَالْاَرْضَ، وَلَا يَئُوْدُهُۥ حِفْظُهُمَا، وَهُوَ الْعَلِيُّ الْعَظِيْمُ.', 'Bismillaahir Rahmaanir Raheem. Allahu laa ilaaha illa huwa al-hayyul qayyuum, Laa ta''khudhuhu sinatun wa laa nawm, Lahu maa fis-samaawaati wa maa fil-ard, Man dhal-ladhee yashfa''u ''indahu illaa bi-idhnih, Ya''lamu maa bayna aydeehim wa maa khalfahum, Wa laa yuheetoona bishay''im-min ''ilmihi illaa bimaa shaa'', Wasi''a kursiyyuhu as-samaawaati wal-ard, Wa laa ya''ooduhu hifdhuhumaa wa huwal-''aliyyul-''adheem.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. Allah – there is no deity except Him, the Ever-Living, the Sustainer of ALL existence. Neither drowsiness overtakes Him nor sleep. To Him belongs whatever is in the heavens and whatever is on the earth. Who is it that can intercede with Him except by His permission? He knows what is [presently] before them and what will be after them, and they encompass not a thing of His knowledge except for what He wills. His Kursi extends over the heavens and the earth, and their preservation tires Him not. And He is the Most High, the Most Great.', 1, NULL, 'duas_after_salah', 'The Messenger of Allah (ﷺ) said: "Whoever reads Ayatul Kursi at the end of (after) each mandatory prayer, nothing prevents him from entering paradise except death." Sunan an-Nasa''i al-Kubra, no. 9848, and al-Tabarani, no. 7532. Also the virtues of Ayatul Kursi: 1) The Greatest verse in the Quran; 2) Protection from the jinn; 3) When recited in a house, Shaytan leaves; 4) Ayatul Kursi contains the greatest name of Allah.', 'Surah Al Baqarah 2:255 | Sunan an-Nasa''i al-Kubra no. 9848 | al-Tabarani no. 7532 | Hisn al-Muslim 68', 9, 'The Messenger of Allah (ﷺ) said: "Whoever reads Ayatul Kursi at the end of (after) each mandatory prayer, nothing prevents him from entering paradise except death." Sunan an-Nasa''i al-Kubra, no. 9848, and al-Tabarani, no. 7532. Also the virtues of Ayatul Kursi: 1) The Greatest verse in the Quran; 2) Protection from the jinn; 3) When recited in a house, Shaytan leaves; 4) Ayatul Kursi contains the greatest name of Allah.'),
  ('salah_after_010', 'THREE times after Fajr and Maghrib', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ هُوَ اللهُ اَحَدٌ. اَللهُ الصَّمَدُ. لَمْ يَلِدْ وَلَمْ يُوْلَدْ. وَلَمْ يَكُنْ لَّهُۥ كُفُوًا اَحَدٌ.', 'Bismillaahir Rahmaanir Raheem. 112:1 Qul huwa Allahu ahad, 112:2 Allahus-samad, 112:3 Lam yalid wa lam yoolad, 112:4 Wa lam yakun lahu kufuwan ahad.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 112:1 Say, "He is Allah, [who is] One. 112:2 Allah, the Eternal Refuge. 112:3 He neither begets nor is born. 112:4 Nor is there to Him any equivalent."', 1, '1 (3 after Fajr/Maghrib)', 'duas_after_salah', 'Mu`adh bin `Abdullah bin Khubaib narrated from his father: We went out on a rainy and extremely dark night, looking for the Messenger of Allah (ﷺ), so that he could lead us in Salat. He said, "Speak." He said, "Say: He is Allah, the One" and Al-Mu''awwidhatain, when you reach evening, and when you reach morning, three times, they will suffice you against everything." Jami` at-Tirmidhi 3575. Narrated Uqbah ibn Amir: The Messenger of Allah (ﷺ) commanded me to recite Mu''awwidhatan (the last two surahs of the Qur''an) after every prayer. Sunan Abi Dawud 1523. (Surahs 112 Al-Ikhlas, 113 Al-Falaq, and 114 An-Nas) These Surahs should be recited in Arabic after each prayer. After the Maghrib and Fajr prayers, they should be recited three times each.', 'Al-Ikhlas | Jami` at-Tirmidhi 3575 | Sunan Abi Dawud 1523 | Sahih al-Bukhari 5015 & 5017 | Hisn al-Muslim 70', 10, 'Mu`adh bin `Abdullah bin Khubaib narrated from his father: We went out on a rainy and extremely dark night, looking for the Messenger of Allah (ﷺ), so that he could lead us in Salat. He said, "Speak." He said, "Say: He is Allah, the One" and Al-Mu''awwidhatain, when you reach evening, and when you reach morning, three times, they will suffice you against everything." Jami` at-Tirmidhi 3575. Narrated Uqbah ibn Amir: The Messenger of Allah (ﷺ) commanded me to recite Mu''awwidhatan (the last two surahs of the Qur''an) after every prayer. Sunan Abi Dawud 1523. (Surahs 112 Al-Ikhlas, 113 Al-Falaq, and 114 An-Nas) These Surahs should be recited in Arabic after each prayer. After the Maghrib and Fajr prayers, they should be recited three times each.'),
  ('salah_after_011', 'THREE times after Fajr and Maghrib', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ اَعُوْذُ بِرَبِّ الْفَلَقِ. مِنْ شَرِّ مَا خَلَقَ. وَمِنْ شَرِّ غَاسِقٍ اِذَا وَقَبَ. وَمِنْ شَرِّ النَّفّٰثٰتِ فِى الْعُقَدِ. وَمِنْ شَرِّ حَاسِدٍ اِذَا حَسَدَ.', 'Bismillaahir Rahmaanir Raheem. 113:1 Qul a''oodhu bi rabbil-falaq, 113:2 Min sharri maa khalaq, 113:3 Wa min sharri ghaasiqin idhaa waqab, 113:4 Wa min sharri an-naffaathaati fil-''uqad, 113:5 Wa min sharri haasidin idhaa hasad.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 113:1 Say, "I seek refuge in the Lord of daybreak. 113:2 From the evil of that which He created. 113:3 And from the evil of darkness when it settles. 113:4 And from the evil of the blowers in knots. 113:5 And from the evil of an envier when he envies."', 1, '1 (3 after Fajr/Maghrib)', 'duas_after_salah', 'Mu`adh bin `Abdullah bin Khubaib narrated from his father: We went out on a rainy and extremely dark night, looking for the Messenger of Allah (ﷺ), so that he could lead us in Salat. He said, "Speak." He said, "Say: He is Allah, the One" and Al-Mu''awwidhatain, when you reach evening, and when you reach morning, three times, they will suffice you against everything." Same hadith chain as Al-Ikhlas. (Surahs 112 Al-Ikhlas, 113 Al-Falaq, and 114 An-Nas) These Surahs should be recited in Arabic after each prayer. After the Maghrib and Fajr prayers, they should be recited three times each.', 'Al-Falaq | Jami` at-Tirmidhi 3575 | Sunan Abi Dawud 1523 | Sahih al-Bukhari 5015 & 5017 | Hisn al-Muslim 70', 11, 'Mu`adh bin `Abdullah bin Khubaib narrated from his father: We went out on a rainy and extremely dark night, looking for the Messenger of Allah (ﷺ), so that he could lead us in Salat. He said, "Speak." He said, "Say: He is Allah, the One" and Al-Mu''awwidhatain, when you reach evening, and when you reach morning, three times, they will suffice you against everything." Same hadith chain as Al-Ikhlas. (Surahs 112 Al-Ikhlas, 113 Al-Falaq, and 114 An-Nas) These Surahs should be recited in Arabic after each prayer. After the Maghrib and Fajr prayers, they should be recited three times each.'),
  ('salah_after_012', 'THREE times after Fajr and Maghrib', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ اَعُوْذُ بِرَبِّ النَّاسِ. مَلِكِ النَّاسِ. اِلٰهِ النَّاسِ. مِنْ شَرِّ الْوَسْوَاسِ الْخَنَّاسِ. الَّذِىْ يُوَسْوِسُ فِىْ صُدُوْرِ النَّاسِ. مِنَ الْجِنَّةِ وَالنَّاسِ.', 'Bismillaahir Rahmaanir Raheem. 114:1 Qul a''oodhu bi rabbin-naas, 114:2 Malikin-naas, 114:3 Ilaahin-naas, 114:4 Min sharril-waswaasil-khannaas, 114:5 Alladhee yuwaswisu fee sudoorin-naas, 114:6 Minal-jinnati wan-naas.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 114:1 Say, "I seek refuge in the Lord of mankind. 114:2 The Sovereign of mankind. 114:3 The God of mankind. 114:4 From the evil of the retreating whisperer. 114:5 Who whispers [evil] into the breasts of mankind. 114:6 From among the jinn and mankind."', 1, '1 (3 after Fajr/Maghrib)', 'duas_after_salah', 'Same hadith chain as Al-Ikhlas / Al-Falaq.', 'An-Naas | Jami` at-Tirmidhi 3575 | Sunan Abi Dawud 1523 | Sahih al-Bukhari 5015 & 5017 | Hisn al-Muslim 70', 12, 'Same hadith chain as Al-Ikhlas / Al-Falaq.'),
  ('salah_after_013', 'After every Fard Salah', 'لَا اِلٰهَ اِلَّا اللّٰهُ وَحْدَهُ لَا شَرِيْكَ لَهُ، لَهُ الْمُلْكُ، وَلَهُ الْحَمْدُ، وَهُوَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ، اَللّٰهُمَّ لَا مَانِعَ لِمَا اَعْطَيْتَ، وَلَا مُعْطِىَ لِمَا مَنَعْتَ، وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ', 'Laa ilaaha illallaah, Wahdahu laa shareeka lah, Lahul mulku wa lahul hamd, Wahuwa ''ala kulli shay''in qadeer, Allahumma laa maani''a limaa a''tayta, Wa laa mu''tiya limaa mana''ta, Wa laa yanfa''u dhal-jaddi minkal-jadd.', 'None has the right to be worshipped except Allah alone, He has no partner, His is the dominion and His is the praise, and He is Able to do all things. O Allah, there is none who can withhold what You give, and none may give what You have withheld, and the might of the mighty person cannot benefit him against You.', 1, NULL, 'duas_after_salah', 'Narrated Warrad (RA) (the freed slave of Al-Mughira bin Shu`ba): Al-Mughira (RA) wrote to Muawiya bin Abu Sufyan that Allah''s Messenger (ﷺ) used to say at the end of every prayer after the Taslim, "La ilaha illa-l-lahu wahdahu la sharika lahu; lahu-l-mulk wa lahu-l-hamd, wahuwa ''ala kulli shai''in qadir. Allahumma la mani''a Lima a taita, wa la mu''ta Lima mana''ta, wa la yanfa''u dhal-jaddu minkal-jadd."', 'Sahih al-Bukhari 6330 | Hisn al-Muslim 67', 13, 'Narrated Warrad (RA) (the freed slave of Al-Mughira bin Shu`ba): Al-Mughira (RA) wrote to Muawiya bin Abu Sufyan that Allah''s Messenger (ﷺ) used to say at the end of every prayer after the Taslim, "La ilaha illa-l-lahu wahdahu la sharika lahu; lahu-l-mulk wa lahu-l-hamd, wahuwa ''ala kulli shai''in qadir. Allahumma la mani''a Lima a taita, wa la mu''ta Lima mana''ta, wa la yanfa''u dhal-jaddu minkal-jadd."'),
  ('salah_after_014', 'Before offering personal Du''a', 'اَللّٰهُمَّ صَلِّ عَلٰى مُحَمَّدٍ، وَعَلٰۤى اٰلِ مُحَمَّدٍ، كَمَا صَلَّيْتَ عَلٰى اِبْرَاهِيْمَ، وَعَلٰۤى اٰلِ اِبْرَاهِيْمَ، اِنَّكَ حَمِيْدٌ مَّجِيْدٌ. اَللّٰهُمَّ بَارِكْ عَلٰى مُحَمَّدٍ، وَعَلٰۤى اٰلِ مُحَمَّدٍ، كَمَا بَارَكْتَ عَلٰۤى اِبْرَاهِيْمَ، وَعَلٰۤى اٰلِ اِبْرَاهِيْمَ، اِنَّكَ حَمِيْدٌ مَّجِيْدٌ.', 'Allaahumma salli ''ala Muhammad, Wa ''ala aali Muhammad, Kamaa sallayta ''ala Ibraaheem, Wa ''ala aali Ibraaheem, Innaka hameedum majeed. Allaahumma baarik ''ala Muhammad, Wa ''ala aali Muhammad, Kamaa baarakta ''ala Ibraaheem, Wa ''ala aali Ibraaheem, Innaka hameedum majeed.', 'O Allah, let Your Blessings come upon Muhammad and the family of Muhammad, as you have blessed Ibrahim and his family. Truly, You are Praiseworthy and Glorious. O Allah, bless Muhammad and the family of Muhammad, as you have blessed Ibrahim and his family. Truly, You are Praiseworthy and Glorious.', 1, NULL, 'duas_after_salah', 'NOTE: There are no conditions or requirements to recite Durood after salah; however, it is preferable to invoke blessings on the Prophet (ﷺ) before any supplication. Narrated Fudalah ibn Ubayd (RA): The Messenger of Allah (ﷺ) heard a person supplicating during prayer. He did not mention the greatness of Allah, nor did he invoke blessings on the Messenger of Allah (ﷺ). The Messenger of Allah (ﷺ) said: He made haste. He then called him and said either to him or to any other person: If any of you prays, he should mention the exaltation of his Lord in the beginning and praise Him; he should then invoke blessings on the Prophet (ﷺ); thereafter he should supplicate Allah for anything he wishes. Sunan Abi Dawud 1481. Umar bin Al-Khattab narrated: "Indeed the supplication stops between the heavens and the earth. Nothing of it is raised up until you send Salat upon your Prophet." Jami` at-Tirmidhi 486. Abu Umamah narrated: It was said: ''O Messenger of Allah, which supplication is most likely to be listened to?'' He said: ''(During) the last part of the night, and at the end of the obligatory prayers.'' Jami` at-Tirmidhi 3499. Narrated `Abdur-Rahman bin Abi Laila (RA): Ka`b bin `Ujra (RA) met me and said, "Shall I give you a present? Once the Prophet (ﷺ) came to us and we said, ''O Allah''s Messenger ! We know how to greet you; but how to send ''Salat'' upon you? He said, ''Say: Allahumma Salli ala Muhammadin wa `ala `Ali Muhammadin, kama sal-laita ''ala all Ibrahima inna ka Hamidun Majid. Allahumma barik ''ala all Muhammadin, kama barakta ''ala all Ibrahima, inna ka Hamidun Majid."', 'Sunan Abi Dawud 1481 | Jami` at-Tirmidhi 486 | Jami` at-Tirmidhi 3499 | Sahih al-Bukhari 6357', 14, 'NOTE: There are no conditions or requirements to recite Durood after salah; however, it is preferable to invoke blessings on the Prophet (ﷺ) before any supplication. Narrated Fudalah ibn Ubayd (RA): The Messenger of Allah (ﷺ) heard a person supplicating during prayer. He did not mention the greatness of Allah, nor did he invoke blessings on the Messenger of Allah (ﷺ). The Messenger of Allah (ﷺ) said: He made haste. He then called him and said either to him or to any other person: If any of you prays, he should mention the exaltation of his Lord in the beginning and praise Him; he should then invoke blessings on the Prophet (ﷺ); thereafter he should supplicate Allah for anything he wishes. Sunan Abi Dawud 1481. Umar bin Al-Khattab narrated: "Indeed the supplication stops between the heavens and the earth. Nothing of it is raised up until you send Salat upon your Prophet." Jami` at-Tirmidhi 486. Abu Umamah narrated: It was said: ''O Messenger of Allah, which supplication is most likely to be listened to?'' He said: ''(During) the last part of the night, and at the end of the obligatory prayers.'' Jami` at-Tirmidhi 3499. Narrated `Abdur-Rahman bin Abi Laila (RA): Ka`b bin `Ujra (RA) met me and said, "Shall I give you a present? Once the Prophet (ﷺ) came to us and we said, ''O Allah''s Messenger ! We know how to greet you; but how to send ''Salat'' upon you? He said, ''Say: Allahumma Salli ala Muhammadin wa `ala `Ali Muhammadin, kama sal-laita ''ala all Ibrahima inna ka Hamidun Majid. Allahumma barik ''ala all Muhammadin, kama barakta ''ala all Ibrahima, inna ka Hamidun Majid."'),
  ('sleep_before_002', 'Blowing into the palms 1', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ هُوَ اللهُ اَحَدٌ. اَللهُ الصَّمَدُ. لَمْ يَلِدْ وَلَمْ يُوْلَدْ. وَلَمْ يَكُنْ لَّهُۥ كُفُوًا اَحَدٌ.', 'Bismillaahir Rahmaanir Raheem. 112:1 Qul huwa Allahu ahad, 112:2 Allahus-samad, 112:3 Lam yalid wa lam yoolad, 112:4 Wa lam yakun lahu kufuwan ahad.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 112:1 Say, "He is Allah, [who is] One. 112:2 Allah, the Eternal Refuge. 112:3 He neither begets nor is born. 112:4 Nor is there to Him any equivalent."', 1, NULL, 'duas_before_sleep', 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.', 'Sura Al-Ikhlas | Sahih al-Bukhari 5017', 2, 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.'),
  ('sleep_before_003', 'Blowing into the palms 2', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ اَعُوْذُ بِرَبِّ الْفَلَقِ. مِنْ شَرِّ مَا خَلَقَ. وَمِنْ شَرِّ غَاسِقٍ اِذَا وَقَبَ. وَمِنْ شَرِّ النَّفّٰثٰتِ فِى الْعُقَدِ. وَمِنْ شَرِّ حَاسِدٍ اِذَا حَسَدَ.', 'Bismillaahir Rahmaanir Raheem. 113:1 Qul a''oodhu bi rabbil-falaq, 113:2 Min sharri maa khalaq, 113:3 Wa min sharri ghaasiqin idhaa waqaab, 113:4 Wa min sharri an-naffaathaati fil-''uqad, 113:5 Wa min sharri haasidin idhaa hasad.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 113:1 Say, "I seek refuge in the Lord of daybreak. 113:2 From the evil of that which He created. 113:3 And from the evil of darkness when it settles. 113:4 And from the evil of the blowers in knots. 113:5 And from the evil of an envier when he envies."', 1, NULL, 'duas_before_sleep', 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.', 'Al-Falaq | Sahih al-Bukhari 5017', 3, 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.'),
  ('sleep_before_004', 'Blowing into the palms 3', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ اَعُوْذُ بِرَبِّ النَّاسِ. مَلِكِ النَّاسِ. اِلٰهِ النَّاسِ. مِنْ شَرِّ الْوَسْوَاسِ الْخَنَّاسِ. الَّذِىْ يُوَسْوِسُ فِىْ صُدُوْرِ النَّاسِ. مِنَ الْجِنَّةِ وَالنَّاسِ.', 'Bismillaahir Rahmaanir Raheem. 114:1 Qul a''oodhu bi rabbin-naas, 114:2 Malikin-naas, 114:3 Ilaahin-naas, 114:4 Min sharril-waswaasil-khannaas, 114:5 Alladhee yuwaswisu fee sudoorin-naas, 114:6 Minal-jinnati wan-naas.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 114:1 Say, "I seek refuge in the Lord of mankind. 114:2 The Sovereign of mankind. 114:3 The God of mankind. 114:4 From the evil of the retreating whisperer. 114:5 Who whispers [evil] into the breasts of mankind. 114:6 From among the jinn and mankind."', 1, NULL, 'duas_before_sleep', 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.', 'An-Nas | Sahih al-Bukhari 5017', 4, 'Narrated `Aisha (RA): Whenever the Prophet (ﷺ) went to bed every night, he used to cup his hands together and blow over it after reciting Surat Al-Ikhlas, Surat Al-Falaq and Surat An-Nas, and then rub his hands over whatever parts of his body he was able to rub, starting with his head, face and front of his body. He used to do that three times.'),
  ('sleep_before_005', 'Ayatul Kursi', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. اَللّٰهُ لَآ اِلٰهَ اِلَّا هُوَ الْحَىُّ الْقَيُّوْمُ، لَا تَأْخُذُهُۥ سِنَةٌ وَّلَا نَوْمٌ، لَهُ مَا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِ، مَنْ ذَا الَّذِىْ يَشْفَعُ عِنْدَهُۥ اِلَّا بِاِذْنِهِۦ، يَعْلَمُ مَا بَيْنَ اَيْدِيْهِمْ وَمَا خَلْفَهُمْ، وَلَا يُحِيْطُوْنَ بِشَىْءٍ مِّنْ عِلْمِهِۦۤ اِلَّا بِمَا شَآءَ، وَسِعَ كُرْسِيُّهُ السَّمٰوٰتِ وَالْاَرْضَ، وَلَا يَئُوْدُهُۥ حِفْظُهُمَا، وَهُوَ الْعَلِيُّ الْعَظِيْمُ.', 'Bismillaahir Rahmaanir Raheem. 2:255 Allahu laa ilaaha illa huwa al-hayyul qayyoom, Laa ta''khudhuhu sinatun wa laa nawm, Lahu maa fis-samaawaati wa maa fil-ard, Man dhal-ladhee yashfa''u ''indahu illaa bi-idhnih, Ya''lamu maa bayna aydeehim wa maa khalfahum, Wa laa yuheetoona bishay''im-min ''ilmihi illaa bimaa shaa'', Wasi''a kursiyyuhu as-samaawaati wal-ard, Wa laa ya''ooduhu hifdhuhumaa wa huwal-''aliyyul-''adheem.', 'In the name of Allah, the Entirely Merciful, the Especially Merciful. 2:255 Allah – there is no deity except Him, the Ever-Living, the Sustainer of [all] existence. Neither drowsiness overtakes Him nor sleep. To Him belongs whatever is in the heavens and whatever is on the earth. Who is it that can intercede with Him except by His permission? He knows what is [presently] before them and what will be after them, and they encompass not a thing of His knowledge except for what He wills. His Kursi extends over the heavens and the earth, and their preservation tires Him not. And He is the Most High, the Most Great.', 1, NULL, 'duas_before_sleep', 'Narrated by Abu Huraira (RA): Allah''s Apostle (ﷺ) ordered me to guard the Zakat revenue of Ramadan. Then somebody came to me and started stealing of the foodstuff. I caught him and said: "I will take you to Allah''s Messenger (ﷺ)." Then Abu Huraira described the whole narration and said, that person said to me: "Please don''t take me to Allah''s Messenger (ﷺ) and I will tell you a few words by which Allah will benefit you." He said: "When you go to your bed, recite Ayatul Kursi (2:255) for then there will be a guard from Allah who will protect you all night long, and Shaytan will not be able to come near you till dawn." When the Prophet (ﷺ) heard the story he said to me: "He who came to you at night, told you the truth although he is a liar and it was Shaytan."', 'Surah Al Baqarah 2: 255 | Sahih Al Bukhari 5010', 5, 'Narrated by Abu Huraira (RA): Allah''s Apostle (ﷺ) ordered me to guard the Zakat revenue of Ramadan. Then somebody came to me and started stealing of the foodstuff. I caught him and said: "I will take you to Allah''s Messenger (ﷺ)." Then Abu Huraira described the whole narration and said, that person said to me: "Please don''t take me to Allah''s Messenger (ﷺ) and I will tell you a few words by which Allah will benefit you." He said: "When you go to your bed, recite Ayatul Kursi (2:255) for then there will be a guard from Allah who will protect you all night long, and Shaytan will not be able to come near you till dawn." When the Prophet (ﷺ) heard the story he said to me: "He who came to you at night, told you the truth although he is a liar and it was Shaytan."'),
  ('sleep_before_006', 'Al Baqarah 285', 'اٰمَنَ الرَّسُوْلُ بِمَآ اُنْزِلَ اِلَيْهِ مِنْ رَّبِّهٖ وَالْمُؤْمِنُوْنَ، كُلٌّ اٰمَنَ بِاللّٰهِ وَمَلٰٓئِكَتِهٖ وَكُتُبِهٖ وَرُسُلِهٖ، لَا نُفَرِّقُ بَيْنَ اَحَدٍ مِّنْ رُّسُلِهٖ، وَقَالُوْا سَمِعْنَا وَاَطَعْنَا، غُفْرَانَكَ رَبَّنَا وَاِلَيْكَ الْمَصِيْرُ.', '2:285 Aamanar-rasoolu bimaa unzila ilaihi mir-rabbihee wal-mu''minoon, Kullun aamana billaahi wa malaa''ikatihi wa kutubihi wa rusulih, Laa nufarriqu bayna ahadim mir-rusulih, Wa qaaloo sami''naa wa ata''naa, Ghufraanaka rabbanaa wa ilaikal-maseer.', '2:285 The Messenger has believed in what was revealed to him from his Lord, and [so have] the believers. All of them have believed in Allah and His angels and His books and His messengers, [saying], We make no distinction between any of His messengers. And they say, We hear and we obey. [We seek] Your forgiveness, our Lord, and to You is the [final] destination.', 1, NULL, 'duas_before_sleep', 'Narrated Abu Mas`ud al-Ansari (RA): The Prophet (ﷺ) said, "If one recites the last two verses of Surat al-Baqarah at night, it is sufficient for him (for that night)."', 'Al Baqarah 2:285 | Sahih al-Bukhari 5040', 6, 'Narrated Abu Mas`ud al-Ansari (RA): The Prophet (ﷺ) said, "If one recites the last two verses of Surat al-Baqarah at night, it is sufficient for him (for that night)."'),
  ('sleep_before_007', 'Al Baqarah 286', 'لَا يُكَلِّفُ اللّٰهُ نَفْسًا اِلَّا وُسْعَهَا، لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ، رَبَّنَا لَا تُؤَاخِذْنَآ اِنْ نَّسِيْنَآ اَوْ اَخْطَأْنَا، رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ اِصْرًا كَمَا حَمَلْتَهٗ عَلَى الَّذِيْنَ مِنْ قَبْلِنَا، رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهٖ، وَاعْفُ عَنَّا، وَاغْفِرْ لَنَا، وَارْحَمْنَا، اَنْتَ مَوْلٰىنَا، فَانْصُرْنَا عَلَى الْقَوْمِ الْكٰفِرِيْنَ.', '2:286 Laa yukallifullaahu nafsan illaa wus''ahaa, Lahaa maa kasabat wa ''alaihaa maktasabat, Rabbanaa laa tu''aakhidhnaa in naseenaa aw akhta''naa, Rabbanaa wa laa tahmil ''alainaa isran kamaa hamaltahoo ''alal-ladheena min qablinaa, Rabbanaa wa laa tuhammilnaa maa laa taaqata lanaa bih, Wa''fu ''annaa waghfir lanaa warhamnaa, Anta mawlaanaa fansurnaa ''alal-qawmil-kaafireen.', '2:286 Allah does not charge a soul except [with that within] its capacity. It will have [the consequence of] what [good] it has gained, and it will bear [the consequence of] what [evil] it has earned. Our Lord, do not impose blame upon us if we have forgotten or erred. Our Lord, and lay not upon us a burden like that which You laid upon those before us. Our Lord, and burden us not with that which we have no ability to bear. And pardon us; and forgive us; and have mercy upon us. You are our protector, so give us victory over the disbelieving people.', 1, NULL, 'duas_before_sleep', 'Narrated Abu Mas`ud al-Ansari (RA): The Prophet (ﷺ) said, "If one recites the last two verses of Surat al-Baqarah at night, it is sufficient for him (for that night)."', 'Al Baqarah 2:286 | Sahih al-Bukhari 5040', 7, 'Narrated Abu Mas`ud al-Ansari (RA): The Prophet (ﷺ) said, "If one recites the last two verses of Surat al-Baqarah at night, it is sufficient for him (for that night)."'),
  ('sleep_before_008', 'Surah al-Kafirun', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ. قُلْ يٰۤاَيُّهَا الْكٰفِرُوْنَ. لَآ اَعْبُدُ مَا تَعْبُدُوْنَ. وَلَآ اَنْتُمْ عٰبِدُوْنَ مَآ اَعْبُدُ. وَلَآ اَنَا عَابِدٌ مَّا عَبَدْتُّمْ. وَلَآ اَنْتُمْ عٰبِدُوْنَ مَآ اَعْبُدُ. لَكُمْ دِيْنُكُمْ وَلِيَ دِيْنِ.', 'Bismillah hir Rahman nir Raheem. 109:1 Qul ya ayyuhal kaafiroon, 109:2 La a''budu maa ta''budoon, 109:3 Wa laa antum aabidoona maa a''bud, 109:4 Wa laa ana aabidum maa abattum, 109:5 Wa laa antum aabidoona maa a''bud, 109:6 Lakum deenukum wa liya deen.', 'In the name of Allah, the Most Gracious, the Most Merciful. 109:1 Say, "O disbelievers, 109:2 I do not worship what you worship. 109:3 Nor are you worshippers of what I worship. 109:4 Nor will I be a worshipper of what you worship. 109:5 Nor will you be worshippers of what I worship. 109:6 For you is your religion, and for me is my religion."', 1, NULL, 'duas_before_sleep', 'Farwah b. Nawfal (RA) quoted his father as saying that the Prophet (ﷺ) said to Nawfal (his father): Recite (Al-Kafirun 109) ''Say, O you disbelievers!'' and then go to sleep at its end, for it is a declaration of freedom from polytheism.', 'Sunan Abi Dawud 5055', 8, 'Farwah b. Nawfal (RA) quoted his father as saying that the Prophet (ﷺ) said to Nawfal (his father): Recite (Al-Kafirun 109) ''Say, O you disbelievers!'' and then go to sleep at its end, for it is a declaration of freedom from polytheism.'),
  ('sleep_before_009', 'Prior to Sleeping 1', 'اَللّٰهُمَّ بِاسْمِكَ اَمُوْتُ وَاَحْيَا', 'Allahumma bismika amutu wa ahya.', 'O Allah in Your name, I die and I live.', 1, NULL, 'duas_before_sleep', 'Narrated Abu Dhar (RA): Whenever the Prophet (ﷺ) lay on his bed, he used to say: "Allahumma bismika amutu wa ahya," and when he woke up he would say: "Al-hamdu lil-lahilladhi ahyana ba''da ma an atana, wa ilaihi an-nushur."', 'Sahih al-Bukhari 6325', 9, 'Narrated Abu Dhar (RA): Whenever the Prophet (ﷺ) lay on his bed, he used to say: "Allahumma bismika amutu wa ahya," and when he woke up he would say: "Al-hamdu lil-lahilladhi ahyana ba''da ma an atana, wa ilaihi an-nushur."'),
  ('sleep_before_010', 'Prior to Sleeping 2', 'اَللّٰهُمَّ اَسْلَمْتُ وَجْهِيْ اِلَيْكَ، وَفَوَّضْتُ اَمْرِىْ اِلَيْكَ، وَاَلْجَأْتُ ظَهْرِيْ اِلَيْكَ، رَغْبَةً وَّرَهْبَةً اِلَيْكَ، لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ اِلَّآ اِلَيْكَ، اٰمَنْتُ بِكِتَابِكَ الَّذِىْۤ اَنْزَلْتَ، وَبِنَبِيِّكَ الَّذِىْۤ اَرْسَلْتَ.', 'Allahumma aslamtu wajhi ilaik, Wa fawwadtu ''amri ilaik, Wa alja''tu dhahri ilaik, Raghbatan wa rahbatan ilaik, La malja''a wa la manja minka illa ilaik, Aamantu bikitabik al-ladhi anzalt, Wa binabiyyik al-ladhi arsalt.', 'O Allah! I have submitted myself to You, I have turned my face to You, committed my affairs to You, and depend on You for protection out of desire for You and out of fear of You (expecting Your reward and fearing Your punishment). There is no refuge and no place of safety from You but with You. I believed in the Book You have revealed, and in the Prophet You have sent (i.e., Muhammad ﷺ).', 1, NULL, 'duas_before_sleep', 'Narrated Al-Bara bin `Azib (RA): Allah''s Messenger (ﷺ) said to me, "When you want to go to bed, perform ablution as you do for prayer, then lie down on your right side and say: ''Allahumma aslamtu wajhi ilaika, wa fawwadtu ''amri ilaika, wa alja''tu dhahri ilaika, raghbatan wa rahbatan ilaika, la malja''a wa la manja minka illa ilaika. Aamantu bikitabik al-ladhi anzalta wa binabiyyik al-ladhi arsalta''. If you should die then (after reciting this) you will die on the religion of Islam (i.e., as a Muslim); so let these words be the last you say (before going to bed)" While I was memorizing it, I said, "Wa birasulika al-ladhi arsalta (in Your Apostle whom You have sent).'' The Prophet (ﷺ) said, "No, but say: Wa binabiyyika al-ladhi arsalta (in Your Prophet whom You have sent)."', 'Sahih al-Bukhari 6311', 10, 'Narrated Al-Bara bin `Azib (RA): Allah''s Messenger (ﷺ) said to me, "When you want to go to bed, perform ablution as you do for prayer, then lie down on your right side and say: ''Allahumma aslamtu wajhi ilaika, wa fawwadtu ''amri ilaika, wa alja''tu dhahri ilaika, raghbatan wa rahbatan ilaika, la malja''a wa la manja minka illa ilaika. Aamantu bikitabik al-ladhi anzalta wa binabiyyik al-ladhi arsalta''. If you should die then (after reciting this) you will die on the religion of Islam (i.e., as a Muslim); so let these words be the last you say (before going to bed)" While I was memorizing it, I said, "Wa birasulika al-ladhi arsalta (in Your Apostle whom You have sent).'' The Prophet (ﷺ) said, "No, but say: Wa binabiyyika al-ladhi arsalta (in Your Prophet whom You have sent)."'),
  ('sleep_before_011', 'Prior to Sleeping 3', 'بِاسْمِكَ رَبِّيْ وَضَعْتُ جَنْبِيْ، وَبِكَ اَرْفَعُهٗ، اِنْ اَمْسَكْتَ نَفْسِىْ فَارْحَمْهَا، وَاِنْ اَرْسَلْتَهَا فَاحْفَظْهَا، بِمَا تَحْفَظُ بِهٖ عِبَادَكَ الصَّالِحِيْنَ', 'Bismika Rabbi wada''tu janbi, Wa bika arfa''uhu, In amsakta nafsi farhamha, Wa in arsaltaha fahfazha, Bima tahfazu bihi ''ibadakas-salihin.', 'With Your Name, my Lord, I place my side upon the bed, and with Your Grace I will raise it up. If You withhold my soul (cause me to die), have mercy on it but if You let it go (let me live), guard it against which You guarded Your pious slaves.', 1, NULL, 'duas_before_sleep', 'Narrated Abu Huraira (RA): The Prophet (ﷺ) said, "When anyone of you go to bed, he should shake out his bed with the inside of his waist sheet, for he does not know what has come on to it after him, and then he should say: ''Bismika Rabbi Wada`tu Janbi wa bika arfa''uhu, In amsakta nafsi farhamha wa in arsaltaha fahfazha bima tahfazu bihi ibadakas-salihin."', 'Sahih al-Bukhari 6320', 11, 'Narrated Abu Huraira (RA): The Prophet (ﷺ) said, "When anyone of you go to bed, he should shake out his bed with the inside of his waist sheet, for he does not know what has come on to it after him, and then he should say: ''Bismika Rabbi Wada`tu Janbi wa bika arfa''uhu, In amsakta nafsi farhamha wa in arsaltaha fahfazha bima tahfazu bihi ibadakas-salihin."'),
  ('sleep_before_012', 'Prior to Sleeping 4', 'اَللّٰهُمَّ قِنِيْ عَذَابَكَ يَوْمَ تَبْعَثُ عِبَادَكَ', 'Allahumma qini ''adhabaka Yauma tab''athu ''ibadaka.', 'O Allah! Guard me against Your punishment on the Day when You will resurrect Your slaves.', 3, NULL, 'duas_before_sleep', 'Narrated Hafsah, Ummul Mu''minin (RA): When the Messenger of Allah (ﷺ) wanted to go to sleep, he put his right hand under his cheek and would then say three times: O Allah! Guard me against Your punishment on the Day when You will resurrect Your slaves.', 'Sunan Abi Dawud 5045', 12, 'Narrated Hafsah, Ummul Mu''minin (RA): When the Messenger of Allah (ﷺ) wanted to go to sleep, he put his right hand under his cheek and would then say three times: O Allah! Guard me against Your punishment on the Day when You will resurrect Your slaves.'),
  ('sleep_before_013', 'Prior to Sleeping 5', 'اَلْحَمْدُ لِلّٰهِ الَّذِىْۤ اَطْعَمَنَا وَسَقَانَا، وَكَفَانَا وَاٰوَانَا، فَكَمْ مِّمَّنْ لَّا كَافِىَ لَهٗ وَلَا مُؤْوِىَ', 'Al-hamdu Lillah alladhi at''amana, Wa saqana, Wa kafana wa awana, Fakam mimman la kafi lahu Wa la muwi.', 'All praise is for Allah, Who fed us and gave us drink, and Who is sufficient for us and has sheltered us, for how many have none to suffice them or shelter them.', 1, NULL, 'duas_before_sleep', 'Anas (RA) reported Allah''s Messenger (ﷺ) as saying: When you go to bed, say: "Praise is due to Allah Who fed us, provided us drink, sufficed us and provided us with shelter, for many a people there is none to suffice and none to provide shelter."', 'Sahih Muslim 2715', 13, 'Anas (RA) reported Allah''s Messenger (ﷺ) as saying: When you go to bed, say: "Praise is due to Allah Who fed us, provided us drink, sufficed us and provided us with shelter, for many a people there is none to suffice and none to provide shelter."'),
  ('sleep_before_014', 'Prior to Sleeping 6', 'اَللّٰهُمَّ اِنَّكَ خَلَقْتَ نَفْسِيْ، وَاَنْتَ تَوَفَّاهَا، لَكَ مَمَاتُهَا وَمَحْيَاهَا، اِنْ اَحْيَيْتَهَا فَاحْفَظْهَا، وَاِنْ اَمَتَّهَا فَاغْفِرْ لَهَا، اَللّٰهُمَّ اِنِّيْۤ اَسْاَلُكَ الْعَافِيَةَ', 'Allahumma innaka khalaqta nafsi, Wa anta tawaffaaha, Laka mamatuha wa mah''yaha, In ahyaytaha fahfazha, Wa in amattaha faghfir laha, Allahumma inni asaluka al-''afiyah.', 'O Allah, You have created my soul and it is for You to take it in death. Its death and its life are in Your hand. If You cause it to live then protect it and if You cause it to die then forgive it. O Allah, I ask You to keep me safe and sound.', 1, NULL, 'duas_before_sleep', 'Abdullah b. ''Umar (RA) commanded a person that as he went to bed, he should say: "O Allah, Thou created my being and it is for Thee to take it to its ultimate goal. And its death and life is due to Thee, and if Thou givest it life, safeguard it; and if Thou bringst death, grant it pardon. O Allah, I beg of Thee safety." A person said to him: Did you hear it from Umar? Thereupon he said: (I have heard from one) who is better than Umar, viz. from Allah''s Messenger (ﷺ). Ibn Nafi reported this on the authority of Abdullah b. Harith but he did not make mention of this that he heard it himself.', 'Sahih Muslim 2712', 14, 'Abdullah b. ''Umar (RA) commanded a person that as he went to bed, he should say: "O Allah, Thou created my being and it is for Thee to take it to its ultimate goal. And its death and life is due to Thee, and if Thou givest it life, safeguard it; and if Thou bringst death, grant it pardon. O Allah, I beg of Thee safety." A person said to him: Did you hear it from Umar? Thereupon he said: (I have heard from one) who is better than Umar, viz. from Allah''s Messenger (ﷺ). Ibn Nafi reported this on the authority of Abdullah b. Harith but he did not make mention of this that he heard it himself.'),
  ('sleep_before_015', 'Prior to Sleeping 7', 'اَللّٰهُمَّ رَبَّ السَّمٰوٰتِ وَرَبَّ الْاَرْضِ وَرَبَّ الْعَرْشِ الْعَظِيْمِ، رَبَّنَا وَرَبَّ كُلِّ شَىْءٍ، فَالِقَ الْحَبِّ وَالنَّوٰى وَمُنْزِلَ التَّوْرَاةِ وَالْاِنْجِيْلِ وَالْفُرْقَانِ، اَعُوْذُ بِكَ مِنْ شَرِّ كُلِّ شَىْءٍ اَنْتَ اٰخِذٌ بِنَاصِيَتِهٖ، اَللّٰهُمَّ اَنْتَ الْاَوَّلُ فَلَيْسَ قَبْلَكَ شَىْءٌ، وَاَنْتَ الْاٰخِرُ فَلَيْسَ بَعْدَكَ شَىْءٌ، وَاَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَىْءٌ، وَاَنْتَ الْبَاطِنُ فَلَيْسَ دُوْنَكَ شَىْءٌ، اِقْضِ عَنَّا الدَّيْنَ وَاَغْنِنَا مِنَ الْفَقْرِ', 'Allahumma Rabb as-samawati wa Rabb al-ard wa Rabb al-''arsh il-''adheem, Rabbana wa Rabba kulli shay''in, Faliq al-habb wa''n-nawa wa munzil at-Tawrati wa''l-Injili wa''l-Furqan, A''udhu bika min sharri kulli shay''in anta akhidhun bi-nasiyatihi. Allahumma anta al-awwalu fa laysa qablaka shay''un, Wa anta al-akhiru fa laysa ba''daka shay''un, Wa anta az-zahiru fa laysa fawqaka shay''un, Wa anta al-batin fa laysa dunaka shay''un, Iqdi ''anna ad-dayna wa aghnina mina al-faqr.', 'O Allah, Lord of the heavens, Lord of the earth and Lord of the mighty Throne, our Lord and Lord of all things, Splitter of the seed and the date stone, Revealer of the Tawrat, the Injil and the Furqan, I seek refuge in You from the evil of every creature that You seize by the forelock. O Allah, You are the First and there is nothing before You; You are the Last and there is nothing after You. You are the Manifest and there is nothing above You; You are the Hidden and there is nothing beyond You. Settle our debt and spare us from poverty.', 1, NULL, 'duas_before_sleep', 'Suhail reported that Abu Salih used to command us: When any one of you intends to go to sleep, he should lie on the bed on his right side and then say this dua.', 'Sahih Muslim 2713a', 15, 'Suhail reported that Abu Salih used to command us: When any one of you intends to go to sleep, he should lie on the bed on his right side and then say this dua.'),
  ('sleep_before_016', 'Prior to Sleeping 8', 'اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِوَجْهِكَ الْكَرِيْمِ، وَكَلِمَاتِكَ التَّآمَّاتِ مِنْ شَرِّ مَا اَنْتَ اٰخِذٌ بِنَاصِيَتِهٖ، اَللّٰهُمَّ اَنْتَ تَكْشِفُ الْمَغْرَمَ وَالْمَأْثَمَ، اَللّٰهُمَّ لَا يُهْزَمُ جُنْدُكَ وَلَا يُخْلَفُ وَعْدُكَ، وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ، سُبْحَانَكَ وَبِحَمْدِكَ', 'Allahumma inni a''udhu bi-wajhika al-karim, Wa kalimatik at-tammati min sharri ma anta akhidhun bi-nasiyatihi; Allahumma anta takshifu al-maghrama wa''l-matham; Allahumma la yuhzamu junduka, Wa la yukhlafu wa''duka, Wa la yanfa''u dha''l-jaddi minka al-jadd. Subhanaka wa bihamdika.', 'O Allah, I seek refuge in Your noble countenance and Your perfect words from the evil of all things that You seize by the forelock. O Allah, You remove debt and sin. O Allah, Your troops will not be defeated, nor Your promise will not be broken, nor can the richness of a rich man avail him anything before You, glory and praise be to You.', 1, NULL, 'duas_before_sleep', 'Narrated Ali ibn AbuTalib (RA): The Messenger of Allah used to say when he lay down this dua. Classed as sahih by an-Nawawi in al-Adhkar P. 111 and by Ibn Hajar in Nataij al-Afkar 2/384.', 'Sunan Abi Dawud 5052', 16, 'Narrated Ali ibn AbuTalib (RA): The Messenger of Allah used to say when he lay down this dua. Classed as sahih by an-Nawawi in al-Adhkar P. 111 and by Ibn Hajar in Nataij al-Afkar 2/384.'),
  ('sleep_before_017', 'Prior to Sleeping 9', 'بِسْمِ اللهِ وَضَعْتُ جَنْبِيْ، اَللّٰهُمَّ اغْفِرْ لِيْ ذَنْبِيْ، وَاَخْسِئْ شَيْطَانِيْ، وَفُكَّ رِهَانِيْ، وَاجْعَلْنِيْ فِىْ النَّدِيِّ الْاَعْلٰى', 'Bismillahi wada''tu janbi, Allahumma ighfir li dhanbi, Wa akhsi shaytani, Wa fukka rihani, Waj''alni fi''n-nadiyyil a''laa.', 'In the name of Allah I lie down. O Allah, forgive me my sins, suppress my shaytan, ransom me and join me with the highest assembly.', 1, NULL, 'duas_before_sleep', 'Narrated AbulAzhar al-Anmari (RA): When the Messenger of Allah went to his bed at night, he would say: in the name of Allah, I have laid down my side for Allah. O Allah! forgive me my sin, drive away my devil, free me from my responsibility, and place me in the highest assembly.', 'Sunan Abi Dawud 5054', 17, 'Narrated AbulAzhar al-Anmari (RA): When the Messenger of Allah went to his bed at night, he would say: in the name of Allah, I have laid down my side for Allah. O Allah! forgive me my sin, drive away my devil, free me from my responsibility, and place me in the highest assembly.'),
  ('sleep_before_018', 'Prior to Sleeping 10', 'اَلْحَمْدُ لِلّٰهِ الَّذِىْ كَفَانِيْ وَاٰوَانِيْ، وَاَطْعَمَنِيْ وَسَقَانِيْ، وَالَّذِىْ مَنَّ عَلَىَّ فَاَفْضَلَ، وَالَّذِىْ اَعْطَانِيْ فَاَجْزَلَ، اَلْحَمْدُ لِلّٰهِ عَلٰى كُلِّ حَالٍ، اَللّٰهُمَّ رَبَّ كُلِّ شَىْءٍ وَّمَلِيْكَهٗ وَاِلٰهَ كُلِّ شَىْءٍ، اَعُوْذُ بِكَ مِنَ النَّارِ', 'Alhamdulillahil-ladhi kafani wa awwani, Wa at''amani wa saqani, Wal-ladhi manna ''alayya fa afdhal, Wal-ladhi a''tani fa ajzal. Alhamdulillahi ''ala kulli hal. Allahumma Rabba kulli shay''in wa malikahu, Wa ilaha kulli shay''in, a''udhu bika min an-nar.', 'Praise be to Allah Who has given me sufficiency, has guarded me, given me food and drink, been most gracious to me, and given to me most lavishly. Praise be to Allah in every circumstance. O Allah! Lord and King of everything, God of everything, I seek refuge in Thee from Hell.', 1, NULL, 'duas_before_sleep', 'Narrated Abdullah ibn Umar (RA): When the Messenger of Allah went to his bed, he would say this dua.', 'Sunan Abi Dawud 5058', 18, 'Narrated Abdullah ibn Umar (RA): When the Messenger of Allah went to his bed, he would say this dua.'),
  ('daily_dua_001', 'Upon Going to Sleep', 'اَللّٰهُمَّ بِاسْمِكَ اَمُوْتُ وَاَحْيَا', 'Allahumma bismika amutu wa ahya.', 'O Allah in Your name, I die and I live.', 1, NULL, 'daily_duas', 'Hudhaifah bin Al-Yaman narrated that when the Prophet wanted to sleep, he would say: O Allah, in Your Name I die and I live. And when he would wake, he would say: Alhamdulillah hil-ladhi ah''yaana ba''damaa amaa''tanaa wa ilay''hin nushoor.', 'Jami` at-Tirmidhi 3417 | Sahih al-Bukhari 7394 | Hisn al-Muslim 105', 1, 'Hudhaifah bin Al-Yaman narrated that when the Prophet wanted to sleep, he would say: O Allah, in Your Name I die and I live. And when he would wake, he would say: Alhamdulillah hil-ladhi ah''yaana ba''damaa amaa''tanaa wa ilay''hin nushoor.'),
  ('daily_dua_002', 'Wake up from Sleep', 'اَلْحَمْدُ لِلّٰهِ الَّذِىْۤ اَحْيَانَا بَعْدَ مَاۤ اَمَاتَنَا وَاِلَيْهِ النُّشُوْرُ', 'Alhamdulillahi hil-ladhi ahyaana ba''da maa amaatana wa ilayhin-nushoor.', 'All praise be to Allah, who gave us life after death (sleep is a form of death) and to Him will we be raised and returned.', 1, NULL, 'daily_duas', 'Hudhaifah bin Al-Yaman (RA) narrated that when the Prophet (ﷺ) wanted to sleep, he would say: "O Allah, in Your Name I die and I live (Allahumma bis''mika, amuu''tu wa ah''ya)." And when he would wake, he would say: "Allah praise is due to Allah who revived my soul after causing its death and to Him is the resurrection (Alhamdulillah hil''ladhi ah''yaana ba''damaa amaa''tanaa wa ilay''hin nushoor)."', 'Jami` at-Tirmidhi 3417', 2, 'Hudhaifah bin Al-Yaman (RA) narrated that when the Prophet (ﷺ) wanted to sleep, he would say: "O Allah, in Your Name I die and I live (Allahumma bis''mika, amuu''tu wa ah''ya)." And when he would wake, he would say: "Allah praise is due to Allah who revived my soul after causing its death and to Him is the resurrection (Alhamdulillah hil''ladhi ah''yaana ba''damaa amaa''tanaa wa ilay''hin nushoor)."'),
  ('daily_dua_003', 'When Leaving Home', 'بِسْمِ اللهِ، تَوَكَّلْتُ عَلَى اللهِ، وَلَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ', 'Bismillah; Tawakkaltu ''ala Allah; Wa laa hawla wa laa quwwata illa billaah.', 'In the Name of Allah, I have placed my trust in Allah, there is no might and no power except by Allah.', 1, NULL, 'daily_duas', 'Narrated Anas ibn Malik (RA): The Prophet (ﷺ) said: When a man goes out of his house and says: "In the name of Allah, I trust in Allah; there is no might and no power but in Allah," the following will be said to him at that time: "You are guided, defended and protected." The devils will go far from him and another devil will say: How can you deal with a man who has been guided, defended and protected?', 'Sunan Abi Dawud 5095 | Hisn al-Muslim 16', 3, 'Narrated Anas ibn Malik (RA): The Prophet (ﷺ) said: When a man goes out of his house and says: "In the name of Allah, I trust in Allah; there is no might and no power but in Allah," the following will be said to him at that time: "You are guided, defended and protected." The devils will go far from him and another devil will say: How can you deal with a man who has been guided, defended and protected?'),
  ('daily_dua_005', 'Entering the Toilet', 'بِسْمِ اللهِ، اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِكَ مِنَ الْخُبُثِ وَالْخَبَآئِثِ', 'Bismillah; Allahumma innee a''oodhu bika minal-khubuthi wal-khabaa''ith.', 'In the name of Allah. O Allah I seek refuge in You from the male female evil and Jinn''s.', 1, NULL, 'daily_duas', 'Narrated Anas bin Malik (RA): Whenever the Prophet (ﷺ) went to the lavatory, he used to say: "Allahumma inni a`udhu bika min al-khubuthi wal khaba''ith." Enter the toilet with left foot first.', 'Sahih al-Bukhari 6322 | Hisn al-Muslim 10', 5, 'Narrated Anas bin Malik (RA): Whenever the Prophet (ﷺ) went to the lavatory, he used to say: "Allahumma inni a`udhu bika min al-khubuthi wal khaba''ith." Enter the toilet with left foot first.'),
  ('daily_dua_006', 'Leaving the Toilet', 'غُفْرَانَكَ', 'Ghufraanaka', 'I seek Your forgiveness', 1, NULL, 'daily_duas', 'Yusuf bin Abi Burdah (RA) narrated: "I heard my father say: ''I entered upon Aishah, and I heard her say: When the Messenger of Allah exited the toilet, he would say: Ghufranaka (I seek Your forgiveness)." Leave the toilet with right foot first.', 'Sunan Ibn Majah 300 | Hisn al-Muslim', 6, 'Yusuf bin Abi Burdah (RA) narrated: "I heard my father say: ''I entered upon Aishah, and I heard her say: When the Messenger of Allah exited the toilet, he would say: Ghufranaka (I seek Your forgiveness)." Leave the toilet with right foot first.'),
  ('daily_dua_007', 'Before the Meals', 'بِسْمِ اللهِ', 'Bismillah', 'In the name of Allah.', 1, NULL, 'daily_duas', 'It was narrated that ''Aishah (RA) said: "The Messenger of Allah was eating food with six of his Companions when a Bedouin came and ate it all in two bites. The Messenger of Allah said: ''If he had said Bismillah, it would have sufficed you (all). When any one of you eats food, let him say Bismillah, and if he forgets to say Bismillah at the beginning, let him say Bismillah fi awwalihi wa akhirih (In the Name of Allah at the beginning and at the end)."', 'Sunan Ibn Majah 3264 | Hisn al-Muslim 178', 7, 'It was narrated that ''Aishah (RA) said: "The Messenger of Allah was eating food with six of his Companions when a Bedouin came and ate it all in two bites. The Messenger of Allah said: ''If he had said Bismillah, it would have sufficed you (all). When any one of you eats food, let him say Bismillah, and if he forgets to say Bismillah at the beginning, let him say Bismillah fi awwalihi wa akhirih (In the Name of Allah at the beginning and at the end)."'),
  ('daily_dua_008', 'Forgetting to recite Bismillah', 'بِسْمِ اللهِ فِىْۤ اَوَّلِهٖ وَاٰخِرِهٖ', 'Bismillahi fee awwalihi wa aakhirih.', 'In the name of Allah in the beginning and end.', 1, NULL, 'daily_duas', 'Narrated Umm Kulthum (RA): From ''Aishah (RA) that the Messenger of Allah (ﷺ) said: "When one of you eats food, then let him say: ''Bismillah.'' If he forgets in the beginning, then let him say: ''Bismillah Fi Awwalihi Wa Akhirih (In the Name of Allah in its beginning and its end)."', 'Jami` at-Tirmidhi 1858 | Hisn al-Muslim 178', 8, 'Narrated Umm Kulthum (RA): From ''Aishah (RA) that the Messenger of Allah (ﷺ) said: "When one of you eats food, then let him say: ''Bismillah.'' If he forgets in the beginning, then let him say: ''Bismillah Fi Awwalihi Wa Akhirih (In the Name of Allah in its beginning and its end)."'),
  ('daily_dua_009', 'After meals', 'Dua 1: اَلْحَمْدُ لِلّٰهِ الَّذِىْۤ اَطْعَمَنِىْ هٰذَا وَرَزَقَنِيْهِ مِنْ غَيْرِ حَوْلٍ مِّنِّيْ وَلَا قُوَّةٍ. Dua 2: اَلْحَمْدُ لِلّٰهِ الَّذِىْۤ اَطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مُسْلِمِيْنَ. Dua 3: اَللّٰهُمَّ بَارِكْ لَنَا فِيْهِ وَاَطْعِمْنَا خَيْرًا مِّنْهُ', 'Dua 1: Alhamdulillahi hil-ladhee at''amanee haadha; Wa razaqaneehi min ghayri hawlin minnee wa laa quwwah. Dua 2: Alhamdulillahi hil-ladhee at''aamana wa saqaana wa ja''alana Muslimeen. Dua 3: Allahumma baarik lanaa feehi wa at''imnaa khayran minhu.', 'Dua 1: Praise is to Allah Who has given me this food, and sustained me with it though I was unable to do it and powerless. Dua 2: All praise belongs to Allah, who fed us and quenched our thirst and made us Muslims. Dua 3: O Allah, You grant us blessings in it and grant us better than it.', 1, NULL, 'daily_duas', 'Sahl bin Mu''adh bin Anas (RA) narrated from his father that: The Messenger of Allah (ﷺ) said: "Whoever eats food and then says: ''All praise is due to Allah who fed me this and granted it as provision to me, without any effort from me nor power (Al-hamdulillah, alladhi at''amani hadha wa razaqanihi min ghairi hawlin minni, wa la quwwatin),'' his past sins shall be forgiven."', 'Daily Duas | After meals', 9, 'Sahl bin Mu''adh bin Anas (RA) narrated from his father that: The Messenger of Allah (ﷺ) said: "Whoever eats food and then says: ''All praise is due to Allah who fed me this and granted it as provision to me, without any effort from me nor power (Al-hamdulillah, alladhi at''amani hadha wa razaqanihi min ghairi hawlin minni, wa la quwwatin),'' his past sins shall be forgiven."'),
  ('daily_dua_010', 'Start of Wudu', 'بِسْمِ اللهِ الرَّحْمٰنِ الرَّحِيْمِ', 'Bismillaahir Rahmaa-nir Raheem', 'In the name of Allah, the Entirely Merciful, the Especially Merciful.', 1, NULL, 'daily_duas', 'Narrated Nu`am Al-Mujmir (RA): Once I went up the roof of the mosque, along with Abu Huraira (RA). He performed ablution and said, "I heard the Prophet (ﷺ) saying, ''On the Day of Resurrection, my followers will be called Al-Ghurr-ul-Muhajjalun from the trace of ablution and whoever can increase the area of his radiance should do so.'' i.e. by performing ablution regularly."', 'Sahih al-Bukhari 136 | Hisn al-Muslim 12', 10, 'Narrated Nu`am Al-Mujmir (RA): Once I went up the roof of the mosque, along with Abu Huraira (RA). He performed ablution and said, "I heard the Prophet (ﷺ) saying, ''On the Day of Resurrection, my followers will be called Al-Ghurr-ul-Muhajjalun from the trace of ablution and whoever can increase the area of his radiance should do so.'' i.e. by performing ablution regularly."'),
  ('daily_dua_011', 'Completion of Wudu', 'اَشْهَدُ اَنْ لَّاۤ اِلٰهَ اِلَّا اللهُ، وَحْدَهٗ لَا شَرِيْكَ لَهٗ، وَاَشْهَدُ اَنَّ مُحَمَّدًا عَبْدُهٗ وَرَسُوْلُهٗ', 'Ash-hadu al-laa ilaaha illallah; Wah''dahu laa shareeka lah; Wa ash-hadu anna; Muhammadan abduhoo wa rasooluh.', 'I testify that there is no one worthy of worship besides Allah. He is all by Himself and has no partner and I testify that Muhammad is Allah''s messenger (Rasool).', 1, NULL, 'daily_duas', 'Uqba b. ''Amir al-Juhani (RA) reported: Verily the Messenger of Allah (ﷺ) said and then narrated (the hadith) like one (mentioned above) except (this) that he said: He who performed ablution and said: I testify that there is no god but Allah, the One, there is no associate with Him and I testify that Muhammad is His servant and His Messenger.', 'Sahih Muslim 234b | Hisn al-Muslim 13', 11, 'Uqba b. ''Amir al-Juhani (RA) reported: Verily the Messenger of Allah (ﷺ) said and then narrated (the hadith) like one (mentioned above) except (this) that he said: He who performed ablution and said: I testify that there is no god but Allah, the One, there is no associate with Him and I testify that Muhammad is His servant and His Messenger.'),
  ('daily_dua_012', 'Entering the Masjid', 'بِسْمِ اللهِ، وَالصَّلَاةُ وَالسَّلَامُ عَلٰى رَسُوْلِ اللهِ، اَللّٰهُمَّ افْتَحْ لِيْۤ اَبْوَابَ رَحْمَتِكَ', 'Bismillah; Was-salaatu was-salaamu ala rasoolillah; Allahummaf-tah lee abwaaba rahmatik.', 'In the Name of Allah, and peace and blessings be upon the Messenger of Allah. O Allah, open the doors of mercy.', 1, NULL, 'daily_duas', 'It was narrated that ''Abdul-Malik bin Sa''eed (RA) said: "I heard Abu Humaid and Abu Usaid say: ''The Messenger of Allah (ﷺ) said: "When any one of you enters the Masjid, let him say: ''Allahumma aftahli abwaba rahmatik (O Allah, open to me the gates of your mercy). And when he leaves let him say: Allahumma inni as''aluka min fadlik (O Allah, I ask You of Your bounty)."', 'Daily Duas | Entering the Masjid', 12, 'It was narrated that ''Abdul-Malik bin Sa''eed (RA) said: "I heard Abu Humaid and Abu Usaid say: ''The Messenger of Allah (ﷺ) said: "When any one of you enters the Masjid, let him say: ''Allahumma aftahli abwaba rahmatik (O Allah, open to me the gates of your mercy). And when he leaves let him say: Allahumma inni as''aluka min fadlik (O Allah, I ask You of Your bounty)."'),
  ('daily_dua_013', 'Leaving the Masjid', 'بِسْمِ اللهِ، وَالصَّلَاةُ وَالسَّلَامُ عَلٰى رَسُوْلِ اللهِ، اَللّٰهُمَّ اِنِّيْۤ اَسْاَلُكَ مِنْ فَضْلِكَ', 'Bismillah; Was-salaatu was-salaamu ala rasoolillah; Allahumma innee as''aluka min fadlik.', 'In the Name of Allah, and peace and blessings be upon the Messenger of Allah. O Allah, I ask for Your favour, O Allah, verily I seek from You, Your bounty.', 1, NULL, 'daily_duas', 'It was narrated that ''Abdul-Malik bin Sa''eed (RA) said: "I heard Abu Humaid and Abu Usaid say: ''The Messenger of Allah (ﷺ) said: "When any one of you enters the Masjid, let him say: Allahumma aftahli abwaba rahmatik. And when he leaves let him say: Allahumma inni as''aluka min fadlik."', 'Daily Duas | Leaving the Masjid', 13, 'It was narrated that ''Abdul-Malik bin Sa''eed (RA) said: "I heard Abu Humaid and Abu Usaid say: ''The Messenger of Allah (ﷺ) said: "When any one of you enters the Masjid, let him say: Allahumma aftahli abwaba rahmatik. And when he leaves let him say: Allahumma inni as''aluka min fadlik."'),
  ('daily_dua_014', 'Answering the Adhan', 'Repeat what the Mu''adhin says except: When the Mu''adhin says: حَىَّ عَلَى الصَّلَاةِ You Say: لَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ. When he says: حَىَّ عَلَى الْفَلَاحِ You Say: لَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ', 'Adhan Response: Repeat what the Mu''adhin says except when: When the Mu''adhin says: Hayya ''alas-salaah, You say: Laa hawla wa laa quwwata illa billaah. When the Mu''adhin says: Hayya ''alal-falaah, You say: Laa hawla wa laa quwwata illa billaah.', 'Repeat what the Mu''adhin says except when: Mu''adhin says: Hasten to the prayer; You Say: There is no might nor power except with Allah. Mu''adhin says: Hasten to real success; You Say: There is no might nor power except with Allah.', 1, NULL, 'daily_duas', 'Narrated Abu Sa`id Al-Khudri (RA): Allah''s Messenger (ﷺ) said, "Whenever you hear the Adhan, say what the Mu''adhin is saying." Sahih al-Bukhari 611. Full Adhan response provided in app: Mu''adhin says: Allahu Akbar (four times) - You say: Allahu Akbar (four times); etc. Including Fajr addition: As-salatu khayrun minan-nawm.', 'Sahih al-Bukhari 611 | Sahih al-Bukhari 609 | Hisn al-Muslim', 14, 'Narrated Abu Sa`id Al-Khudri (RA): Allah''s Messenger (ﷺ) said, "Whenever you hear the Adhan, say what the Mu''adhin is saying." Sahih al-Bukhari 611. Full Adhan response provided in app: Mu''adhin says: Allahu Akbar (four times) - You say: Allahu Akbar (four times); etc. Including Fajr addition: As-salatu khayrun minan-nawm.'),
  ('daily_dua_015', 'Dua after Adhaan', 'اَللّٰهُمَّ رَبَّ هٰذِهِ الدَّعْوَةِ التَّآمَّةِ، وَالصَّلَاةِ الْقَآئِمَةِ، اٰتِ مُحَمَّدًا الْوَسِيْلَةَ وَالْفَضِيْلَةَ، وَابْعَثْهُ مَقَامًا مَّحْمُوْدَا الَّذِىْ وَعَدْتَهٗ، اِنَّكَ لَا تُخْلِفُ الْمِيْعَادَ', 'Allahumma rabba hadhihid da''watit taammah; Was-salatil qaa''imah; Aati Muhammadanil waseelata wal fadeelah; Wab''ath-hu maqaamam mahmoodanil-ladhi wa''adtah; Innaka laa tukhliful mee''aad.', 'Oh Allah! Lord of this perfect call and this prayer to be established, grant Muhammad Al-wasilah (a high and special place in Jannah) and Al-fadheelah (a rank above the rest of creation) and raise him to a praised platform which you have promised him. [Verily You do not neglect promises].', 1, NULL, 'daily_duas', 'Narrated Jabir bin Abdullah (RA): Allah''s Messenger said: Whoever after listening to the Adhan says: Allahumma Rabba hadhihi-dda watit-tammah, was-salatil qa''imah, ati Muhammadan al-wasilata wal-fadilah, wa bath-hu maqaman mahmudan-il-ladhi waadtahu — then my intercession for him will be allowed on the Day of Resurrection.', 'Sahih al-Bukhari 614 | Hisn al-Muslim 25 | Al-Bayhaqi 1/410', 15, 'Narrated Jabir bin Abdullah (RA): Allah''s Messenger said: Whoever after listening to the Adhan says: Allahumma Rabba hadhihi-dda watit-tammah, was-salatil qa''imah, ati Muhammadan al-wasilata wal-fadilah, wa bath-hu maqaman mahmudan-il-ladhi waadtahu — then my intercession for him will be allowed on the Day of Resurrection.'),
  ('daily_dua_016', 'Dua Qunoot', 'DUA QUNOOT 1: اَللّٰهُمَّ اهْدِنَا فِيْمَنْ هَدَيْتَ، وَعَافِنَا فِيْمَنْ عَافَيْتَ، وَتَوَلَّنَا فِيْمَنْ تَوَلَّيْتَ، وَبَارِكْ لَنَا فِيْمَاۤ اَعْطَيْتَ، وَقِنَا شَرَّ مَا قَضَيْتَ. DUA QUNOOT 2: اَللّٰهُمَّ اِنَّا نَسْتَعِيْنُكَ وَنَسْتَغْفِرُكَ وَنُؤْمِنُ بِكَ وَنَتَوَكَّلُ عَلَيْكَ وَنُثْنِىْ عَلَيْكَ الْخَيْرَ', 'Dua Qunoot 1: Allahummahdinaa feeman hadayt; Wa aafinaa feeman aafayt; Wa tawallanaa feeman tawallayt; Wa baarik lanaa feema atayt; Wa qinaa sharra ma qadayt; Innaka taqdee wa laa yuqdaa alayk. Dua Qunoot 2: Allahumma innaa nastaeenuka, Wa nastaghfiruka, Wa nu''minu bika, Wa natawakkalu alayka, Wa nuthnee alaykal khayr; Wa nashkuruka wa laa nakfuruka.', 'Dua Qunoot 1: O Allah, guide us among those whom You have guided, pardon us among those whom You have pardoned, turn to us in friendship among those on whom You have turned in friendship, and bless us in what You have bestowed, and save us from the evil of what You have decreed. Dua Qunoot 2: O Allah! We beg help from You alone; ask forgiveness from You alone, and turn towards You and have faith in You alone.', 1, NULL, 'daily_duas', 'Narrated Al-Hasan ibn Ali (RA): The Messenger of Allah taught me some words that I say during the witr. O Allah, guide me among those Thou hast guided, grant me security among those Thou hast taken into Thy charge, bless me in what Thou hast given, guard me from the evil of what Thou hast decreed.', 'Sunan Abi Dawud 1425 | Sunan Ibn Majah 1178 | Sunan an-Nasai 1745 | Hisn al-Muslim 116 | Al-Bayhaqi 2/210', 16, 'Narrated Al-Hasan ibn Ali (RA): The Messenger of Allah taught me some words that I say during the witr. O Allah, guide me among those Thou hast guided, grant me security among those Thou hast taken into Thy charge, bless me in what Thou hast given, guard me from the evil of what Thou hast decreed.'),
  ('daily_dua_017', 'Janaza Prayer', 'After Takbir #1 (Optional): Surah Al-Fatiha. After Takbir #2: Salawat Ibrahim. After Takbir #3: اَللّٰهُمَّ اغْفِرْ لِحَيِّنَا وَمَيِّتِنَا وَشَاهِدِنَا وَغَائِبِنَا وَصَغِيْرِنَا وَكَبِيْرِنَا وَذَكَرِنَا وَاُنْثٰنَا. اَللّٰهُمَّ مَنْ اَحْيَيْتَهٗ مِنَّا فَاَحْيِهٖ عَلَى الْاِسْلَامِ، وَمَنْ تَوَفَّيْتَهٗ مِنَّا فَتَوَفَّهٗ عَلَى الْاِيْمَانِ. After Takbir #4 (Right): اَلسَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ', 'After Takbir #1: Subhaanaka Allahumma wa bihamdika; Wa tabaarakasmuka; Wa taaalaa jaduka — followed by Al-Fatihah. After Takbir #2: Allaahumma salli ala Muhammad, Wa ala aali Muhammad, Kamaa sallayta ala Ibraaheem. After Takbir #3: Allahummaghfir li-hayyinaa wa mayyitinaa wa shaahidinaa wa ghaaibinaa wa sagheerinaa wa kabeerinaa wa dhakarinaa wa unthaanaa. Allahumma man ahyaitahu minna fa ahyihi alal-Islam, wa man tawaffaitahu minna fa tawaffahu alal-eemaan. Allahumma laa tahrimna ajrahu wa laa tudilanaa baadah. After Takbir #4 (Right): Assalaamu alaykum wa rahmatullah.', 'After Takbir 1: Glory be to You O Allah, and praise be to You, and blessed is Your name, and exalted is Your Majesty, and there is none to be served besides You. After Takbir 2: O Allah, let Your Blessings come upon Muhammad and the family of Muhammad, as you have blessed Ibrahim. After Takbir 3: O Allah, forgive our living and our dead, those present and those absent, our young and our old, our males and our females. O Allah, whom amongst us You keep alive, then let such a life be upon Islam, and whom You take, let such a death be upon faith. After Takbir 4: Peace be upon you and the mercy of Allah.', 1, NULL, 'daily_duas', 'It was narrated that Abu Hurairah (RA) said: When the Messenger of Allah offered the funeral prayer he would say: Allahummaghfir li-hayyina wa mayyitina, wa shahidina wa ghaibina, wa saghirina wa kabirina, wa dhakarina wa unthana. Allahumma man ahyaytahu minna fa-ahyihi alal-Islam, wa man tawaffaytahu minna fa-tawaffahu alal-iman.', 'Sunan Ibn Majah 1498 | Sahih al-Bukhari 1335', 17, 'It was narrated that Abu Hurairah (RA) said: When the Messenger of Allah offered the funeral prayer he would say: Allahummaghfir li-hayyina wa mayyitina, wa shahidina wa ghaibina, wa saghirina wa kabirina, wa dhakarina wa unthana. Allahumma man ahyaytahu minna fa-ahyihi alal-Islam, wa man tawaffaytahu minna fa-tawaffahu alal-iman.'),
  ('daily_dua_018', 'Visiting the Graves', 'اَلسَّلَامُ عَلَيْكُمْ اَهْلَ الدِّيَارِ مِنَ الْمُؤْمِنِيْنَ وَالْمُسْلِمِيْنَ، وَاِنَّاۤ اِنْ شَآءَ اللهُ بِكُمْ لَاحِقُوْنَ، نَسْاَلُ اللهَ لَنَا وَلَكُمُ الْعَافِيَةَ', 'As-salamu alaykum ahla-diyaari minal mumineena wal-Muslimeen; Wa innaa in-shaAllahu bikum lahiqoon; Nasalullaha lana wa-lakumul aafiyah.', 'Peace be upon you, people of this abode, from among the believers and those who are Muslims, and we, by the Will of Allah, shall be joining you. I ask Allah to grant us and you strength.', 1, NULL, 'daily_duas', 'It was narrated from Sulaiman bin Buraidah that his father said: The Messenger of Allah used to teach them, when they went out to the graveyard, to say: As-salamu alaykum ahlad-diyar minal-muminina wal-muslimin, wa inna insha Allah bikum lahiqun, nasalul-laha lana wa lakumul-afiyah (Peace be upon you, O inhabitants of the abodes, believers and Muslims, and we will join you soon if Allah wills. We ask Allah for well-being for us and for you).', 'Sunan Ibn Majah 1547', 18, 'It was narrated from Sulaiman bin Buraidah that his father said: The Messenger of Allah used to teach them, when they went out to the graveyard, to say: As-salamu alaykum ahlad-diyar minal-muminina wal-muslimin, wa inna insha Allah bikum lahiqun, nasalul-laha lana wa lakumul-afiyah (Peace be upon you, O inhabitants of the abodes, believers and Muslims, and we will join you soon if Allah wills. We ask Allah for well-being for us and for you).'),
  ('daily_dua_019', 'On Journey', 'SHORT: سُبْحَانَ الَّذِىْ سَخَّرَ لَنَا هٰذَا وَمَا كُنَّا لَهٗ مُقْرِنِيْنَ، وَاِنَّاۤ اِلٰى رَبِّنَا لَمُنْقَلِبُوْنَ. LONG: بِسْمِ اللهِ، اَلْحَمْدُ لِلهِ، سُبْحَانَ الَّذِىْ سَخَّرَ لَنَا هٰذَا وَمَا كُنَّا لَهٗ مُقْرِنِيْنَ، وَاِنَّاۤ اِلٰى رَبِّنَا لَمُنْقَلِبُوْنَ. اَلْحَمْدُ لِلهِ ×3، اَللهُ اَكْبَرُ ×3، سُبْحَانَكَ اَللّٰهُمَّ اِنِّيْ ظَلَمْتُ نَفْسِيْ فَاغْفِرْ لِيْ، فَاِنَّهٗ لَا يَغْفِرُ الذُّنُوْبَ اِلَّاۤ اَنْتَ', 'Short: Subhana lladhi sakhkhara lana hadha wa ma kunna lahu muqrinin, Wa inna ila Rabbina lamunqalibun. Long: Bismillah, Walhamdulillah. Subhana lladhi sakhkhara lana hadha wa ma kunna lahu muqrinin, Wa inna ila Rabbina lamunqalibun. Alhamdulillah ×3, Allahu Akbar ×3, Subhanaka llahumma inni zalamtu nafsi, Faghfir li, Fa innahu la yaghfirudh-dhunooba illa ant.', 'Short: Glory is to Him Who has provided this for us though we could never have had it by our efforts. Surely, unto our Lord, we are returning. Long: With the Name of Allah. Praise is to Allah. Glory is to Him Who has provided this for us. Praise is to Allah ×3. Allah is the Most Great ×3. Glory is to You. O Allah, I have wronged my own soul. Forgive me, for surely none forgives sins but You.', 1, NULL, 'daily_duas', 'Narrated Ali ibn AbuTalib: Ali ibn Rabia said: I was present with Ali while a beast was brought to him to ride. When he put his foot in the stirrup, he said: In the name of Allah. Then when he sat on its back, he said: Praise be to Allah. He then said: Glory be to Him Who has made this subservient to us, for we had not the strength, and to our Lord do we return.', 'Sunan Abi Dawud 2602', 19, 'Narrated Ali ibn AbuTalib: Ali ibn Rabia said: I was present with Ali while a beast was brought to him to ride. When he put his foot in the stirrup, he said: In the name of Allah. Then when he sat on its back, he said: Praise be to Allah. He then said: Glory be to Him Who has made this subservient to us, for we had not the strength, and to our Lord do we return.'),
  ('daily_dua_020', 'Return From Journey', 'اَللهُ اَكْبَرُ ×3، سُبْحَانَ الَّذِىْ سَخَّرَ لَنَا هٰذَا وَمَا كُنَّا لَهٗ مُقْرِنِيْنَ، وَاِنَّاۤ اِلٰى رَبِّنَا لَمُنْقَلِبُوْنَ. اَللّٰهُمَّ اِنَّا نَسْاَلُكَ فِىْ سَفَرِنَا هٰذَا الْبِرَّ وَالتَّقْوٰى، وَمِنَ الْعَمَلِ مَا تَرْضٰى. اَللّٰهُمَّ هَوِّنْ عَلَيْنَا سَفَرَنَا هٰذَا وَاطْوِ عَنَّا بُعْدَهٗ. اَللّٰهُمَّ اَنْتَ الصَّاحِبُ فِى السَّفَرِ، وَالْخَلِيْفَةُ فِى الْاَهْلِ. اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِكَ مِنْ وَّعْثَآءِ السَّفَرِ، وَكَآبَةِ الْمَنْظَرِ، وَسُوْٓءِ الْمُنْقَلَبِ فِى الْمَالِ وَالْاَهْلِ. اٰئِبُوْنَ، تَآئِبُوْنَ، عَابِدُوْنَ، لِرَبِّنَا حَامِدُوْنَ', 'Allahu Akbar ×3. Subhana lladhi sakhkhara lana hadha wa ma kunna lahu muqrinin, Wa inna ila Rabbina lamunqaliboon. Allahumma inna nasaluka fee safarina hadha al-birra wat-taqwa, Wa mina al-amali ma tardha. Allahumma hawwin alaynaa safaranaa haadhaa watwi annaa budah. Allahumma anta as-sahibu fis-safar, Wal-khaleefatu fil-ahl. Allahumma innee aoodhu bika min watha is-safar, Wa kaabatil-manzar, Wa sooil-munqalabi fil-maali wal-aahl. Aayiboon, taa iboon, aabidoon, li-Rabbina haamidoon.', 'Allah is the Most Great ×3. Glory is to Him Who has provided this for us though we could never have had it by our efforts. Surely, unto our Lord we are returning. O Allah, we ask You on this our journey for goodness and piety, and for works that are pleasing to You. O Allah, lighten this journey for us and make its distance easy for us. O Allah, You are our Companion on the road and the One in Whose care we leave our family. O Allah, I seek refuge in You from this journey hardships, and from the wicked sights in store and from finding our family and property in misfortune upon returning. We return repentant to our Lord, worshipping our Lord, and praising our Lord.', 1, NULL, 'daily_duas', 'Ibn Umar reported: Whenever Allah Messenger mounted his camel to set out on a journey, he would glorify Allah three times, then say this dua. And when he returned, he would add: We return, repentant, worshipping our Lord, and praising Him.', 'Sahih Muslim 1342', 20, 'Ibn Umar reported: Whenever Allah Messenger mounted his camel to set out on a journey, he would glorify Allah three times, then say this dua. And when he returned, he would add: We return, repentant, worshipping our Lord, and praising Him.'),
  ('daily_dua_021', 'When Sneezing', 'اَلْحَمْدُ لِلهِ', 'Alhamdulillah', 'All praise is for Allah.', 1, NULL, 'daily_duas', 'Narrated Abu Huraira: The Prophet said, Allah loves sneezing but dislikes yawning; so if anyone of you sneezes and then praises Allah, every Muslim who hears him (praising Allah) has to say Tashmit to him. But as regards yawning, it is from Satan, so if one of you yawns, he should try his best to stop it, for when anyone of you yawns, Satan laughs at him.', 'Sahih al-Bukhari 6226', 21, 'Narrated Abu Huraira: The Prophet said, Allah loves sneezing but dislikes yawning; so if anyone of you sneezes and then praises Allah, every Muslim who hears him (praising Allah) has to say Tashmit to him. But as regards yawning, it is from Satan, so if one of you yawns, he should try his best to stop it, for when anyone of you yawns, Satan laughs at him.'),
  ('daily_dua_022', 'When Hearing Someone Sneeze', 'يَرْحَمُكَ اللهُ', 'Yarhamuka Allah', 'May Allah have mercy on you.', 1, NULL, 'daily_duas', 'Narrated Abu Huraira (RA): The Prophet said, Allah likes sneezing and dislikes yawning, so if someone sneezes and then praises Allah, then it is obligatory on every Muslim who heard him, to say: May Allah be merciful to you (Yar-hamuka-l-lah). But as regards yawning, it is from Satan, so one must try one best to stop it, if one says Ha when yawning, Satan will laugh at him.', 'Sahih al-Bukhari', 22, 'Narrated Abu Huraira (RA): The Prophet said, Allah likes sneezing and dislikes yawning, so if someone sneezes and then praises Allah, then it is obligatory on every Muslim who heard him, to say: May Allah be merciful to you (Yar-hamuka-l-lah). But as regards yawning, it is from Satan, so one must try one best to stop it, if one says Ha when yawning, Satan will laugh at him.'),
  ('daily_dua_023', 'Sneezers Replies Back', 'يَهْدِيْكُمُ اللهُ وَيُصْلِحُ بَالَكُمْ', 'Yahdeekumullahu wa yuslihu baalakum', 'May Allah guide you and rectify your condition.', 1, NULL, 'daily_duas', 'Abu Hurairah (RA) reported the prophet as saying: When one of you sneezes, he should say: Praise be to Allah in every circumstance, and his brother or his companion should say: May Allah have mercy on you! And he should then reply: May Allah guide you and set right your affairs.', 'Sunan Abi Dawud 5033', 23, 'Abu Hurairah (RA) reported the prophet as saying: When one of you sneezes, he should say: Praise be to Allah in every circumstance, and his brother or his companion should say: May Allah have mercy on you! And he should then reply: May Allah guide you and set right your affairs.'),
  ('daily_dua_024', 'For Good Health', 'اَسْاَلُ اللهَ الْعَظِيْمَ، رَبَّ الْعَرْشِ الْعَظِيْمِ، اَنْ يَّشْفِيَكَ', 'As''alullaha al-''adheem, Rabbal-''arshil-''adheem, An yashfiyak. (Recite seven times)', 'I ask Almighty Allah, Lord of the Magnificent Throne, to make you well. (Recite seven times)', 7, NULL, 'daily_duas', 'Narrated Abdullah ibn Abbas (RA): The Prophet said: If anyone visits a sick whose time (of death) has not come, and says with him (seven times): I ask Allah, the Mighty, the Lord of the mighty Throne, to cure you; Allah will cure him from that disease.', 'Sunan Abi Dawud 3106', 24, 'Narrated Abdullah ibn Abbas (RA): The Prophet said: If anyone visits a sick whose time (of death) has not come, and says with him (seven times): I ask Allah, the Mighty, the Lord of the mighty Throne, to cure you; Allah will cure him from that disease.'),
  ('daily_dua_025', 'Cure of any Illness', 'اَذْهِبِ الْبَاْسَ رَبَّ النَّاسِ، وَاشْفِ اَنْتَ الشَّافِىْ، لَا شِفَآءَ اِلَّا شِفَآؤُكَ، شِفَآءً لَّا يُغَادِرُ سَقَمًا', 'Adh''hibil ba''sa rabban naas; Washfi antash shafee; La shifaa''a illa shifaa''uk; Shifaa''an laa yughaadiru saqamaa.', 'O Lord of the people, remove this pain and cure it, You are the one who cures and there is no one besides You who can cure, grant such a cure that no illness remains.', 1, NULL, 'daily_duas', 'Narrated Aisha (RA): The Prophet used to treat some of his wives by passing his right hand over the place of ailment and used to say, O Lord of the people! Remove the difficulty and bring about healing as You are the Healer. There is no healing but Your Healing, a healing that will leave no ailment.', 'Sahih al-Bukhari 5750 | Sahih Muslim 2191c', 25, 'Narrated Aisha (RA): The Prophet used to treat some of his wives by passing his right hand over the place of ailment and used to say, O Lord of the people! Remove the difficulty and bring about healing as You are the Healer. There is no healing but Your Healing, a healing that will leave no ailment.'),
  ('daily_dua_026', 'Placing Children under Allah''s Protection', 'اُعِيْذُكُمَا بِكَلِمَاتِ اللهِ التَّآمَّةِ، مِنْ كُلِّ شَيْطَانٍ وَّهَامَّةٍ، وَمِنْ كُلِّ عَيْنٍ لَّآمَّةٍ', 'U''eedhukuma bi-kalimaatillaahi at-taammah; Min kulli shaytaanin wa haammatin; Wa min kulli ''aynin laammah.', 'I seek protection for you in the Perfect Words of Allah from every devil and every beast, and from every envious blameworthy eye.', 1, NULL, 'daily_duas', 'Narrated Ibn Abbas (RA): The Prophet used to seek Refuge with Allah for Al-Hasan and Al-Husain and say: Your forefather (i.e. Ibrahim) used to seek Refuge with Allah for Ishmail and Ishaq by reciting the following: O Allah! I seek Refuge with Your Perfect Words from every devil and from poisonous pests and from every evil, harmful, envious eye.', 'Sahih al-Bukhari 3371 | Jami at-Tirmidhi 2060 | Hisn al-Muslim 146', 26, 'Narrated Ibn Abbas (RA): The Prophet used to seek Refuge with Allah for Al-Hasan and Al-Husain and say: Your forefather (i.e. Ibrahim) used to seek Refuge with Allah for Ishmail and Ishaq by reciting the following: O Allah! I seek Refuge with Your Perfect Words from every devil and from poisonous pests and from every evil, harmful, envious eye.'),
  ('daily_dua_027', 'Dua for the Parents', 'رَبَّنَا اغْفِرْ لِيْ وَلِوَالِدَىَّ وَلِلْمُؤْمِنِيْنَ يَوْمَ يَقُوْمُ الْحِسَابُ. رَّبِّ ارْحَمْهُمَا كَمَا رَبَّيٰنِيْ صَغِيْرًا', '14:41 Rabbanaa igh''fir lii wa li-waalidayya wa lil-mu''minīna yawma yaqoobul-hisaab. 17:24 Rabbir hamhumaa kamaa rabbayaani sagheeraa.', '14:41 Our Lord! Forgive me and my parents, and (all) the believers on the Day when the reckoning will be established. 17:24 My Lord! Have mercy on them both as they did care for me when I was young.', 1, NULL, 'daily_duas', 'Narrated Ibn Mas''ud (RA): A man asked the Prophet: What deeds are the best? The Prophet said: 1. To perform the (daily compulsory) prayers at their (early) stated fixed times, 2. to be good and dutiful to one''s own parents, 3. and to participate in Jihad in Allah''s Cause. (Sahih al-Bukhari 7534) — A man will be raised in status in Paradise and will say: Where did this come from? And it will be said: From your son''s praying for forgiveness for you. (Sunan Ibn Majah 3660) — Mu''awiyah bin Jahimah As-Sulami: Jahimah came to the Prophet and said: O Messenger of Allah! I want to go out and fight (in Jihad) and I have come to ask your advice. He said: Do you have a mother? He said: Yes. He said: Then stay with her, for Paradise is beneath her feet. (Sunan an-Nasa''i 3104)', 'Sura Al Ibrahim 14:41 | Sura Al Isra 17:24 | Sahih al-Bukhari 7534 | Sunan Ibn Majah 3660 | Sunan an-Nasa''i 3104', 27, 'Narrated Ibn Mas''ud (RA): A man asked the Prophet: What deeds are the best? The Prophet said: 1. To perform the (daily compulsory) prayers at their (early) stated fixed times, 2. to be good and dutiful to one''s own parents, 3. and to participate in Jihad in Allah''s Cause. (Sahih al-Bukhari 7534) — A man will be raised in status in Paradise and will say: Where did this come from? And it will be said: From your son''s praying for forgiveness for you. (Sunan Ibn Majah 3660) — Mu''awiyah bin Jahimah As-Sulami: Jahimah came to the Prophet and said: O Messenger of Allah! I want to go out and fight (in Jihad) and I have come to ask your advice. He said: Do you have a mother? He said: Yes. He said: Then stay with her, for Paradise is beneath her feet. (Sunan an-Nasa''i 3104)'),
  ('dhikr_028', 'Dhikr 1', 'سُبْحَانَ اللهِ وَبِحَمْدِهٖ، سُبْحَانَ اللهِ الْعَظِيْمِ', 'Subhaanallaahi wa bi-hamdih; Subhaanallaahi al-''adheem.', 'How perfect Allah is and I praise Him. How perfect Allah is, The Supreme.', 1, NULL, 'remembrance_of_allah', 'Narrated Abu Huraira (RA): Allah''s Messenger said, (The following are) two words (sentences or utterances) that are very easy for the tongue to say, and very heavy in the balance (of reward), and most beloved to the Gracious Almighty (And they are): Subhan Allahi wa bi-hamdihi; Subhan Allahi-l-Adhim.', 'Sahih al-Bukhari 6682', 28, 'Narrated Abu Huraira (RA): Allah''s Messenger said, (The following are) two words (sentences or utterances) that are very easy for the tongue to say, and very heavy in the balance (of reward), and most beloved to the Gracious Almighty (And they are): Subhan Allahi wa bi-hamdihi; Subhan Allahi-l-Adhim.'),
  ('dhikr_029', 'Dhikr 2', 'اَللّٰهُمَّ اِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّىْ', 'Allaahumma innaka ''afuwwun; Tuhibbul-''afwa fa''fu ''annee.', 'O Allah You are The One Who pardons greatly, and loves to pardon, so pardon me.', 1, NULL, 'remembrance_of_allah', 'It was narrated from Aisha (RA) that she said: O Messenger of Allah, what do you think I should say in my supplication, if I come upon Laylatul-Qadr? He said: Say: ''Allahumma innaka ''afuwwun tuhibbul-''afwa, fa''fu ''anni (O Allah, You are Forgiving and love forgiveness, so forgive me).', 'Sunan Ibn Majah 3850 | Jami at-Tirmidhi 3513', 29, 'It was narrated from Aisha (RA) that she said: O Messenger of Allah, what do you think I should say in my supplication, if I come upon Laylatul-Qadr? He said: Say: ''Allahumma innaka ''afuwwun tuhibbul-''afwa, fa''fu ''anni (O Allah, You are Forgiving and love forgiveness, so forgive me).'),
  ('dhikr_030', 'Dhikr 3', 'لَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ', 'Laa hawla wa laa quwwata illaa billah', 'There is no might nor power except with Allah.', 1, NULL, 'remembrance_of_allah', 'Narrated Abu Musa (RA): We were in the company of the Prophet on a journey, and whenever we ascended a high place, we used to say Takbir (in a loud voice). The Prophet said, O people! Be kind to yourselves, for you are not calling upon a deaf or an absent one, but You are calling an All-Hearer, and an All-Seer. Then he came to me as I was reciting silently, La haul a wala quwwata illa bil-lah. He said, O Abdullah bin Qais! Say: La haul a walaquwata illa bil-lah, for it is one of the treasures of Paradise. Or he said, Shall I tell you a word which is one of the treasures of Paradise? It is: La haul a wala quwwata illa bil-lah.', 'Sahih al-Bukhari', 30, 'Narrated Abu Musa (RA): We were in the company of the Prophet on a journey, and whenever we ascended a high place, we used to say Takbir (in a loud voice). The Prophet said, O people! Be kind to yourselves, for you are not calling upon a deaf or an absent one, but You are calling an All-Hearer, and an All-Seer. Then he came to me as I was reciting silently, La haul a wala quwwata illa bil-lah. He said, O Abdullah bin Qais! Say: La haul a walaquwata illa bil-lah, for it is one of the treasures of Paradise. Or he said, Shall I tell you a word which is one of the treasures of Paradise? It is: La haul a wala quwwata illa bil-lah.'),
  ('dhikr_031', 'Dhikr 4', 'سُبْحَانَ اللهِ، وَالْحَمْدُ لِلهِ، وَلَا اِلٰهَ اِلَّا اللهُ، وَاللهُ اَكْبَرُ', 'Subhan Allah; Walhamdulillah; Wa laa ilaaha illallah; Wallahu Akbar.', 'Glory be to Allah, All Praise is for Allah, There is No God but Allah, Allah is the Greatest.', 1, NULL, 'remembrance_of_allah', 'Abu Huraira (RA) reported: The Messenger of Allah said: The words: SubhanAllah (Glory be to Allah), Alhamdulillah (All praise is due to Allah), La ilaha illallah (There is no god but Allah), Allahu Akbar (Allah is the Greatest), (above words) are more beloved to me than everything over which the sun rises.', 'Sahih Muslim 2695 | Hisn al-Muslim 261', 31, 'Abu Huraira (RA) reported: The Messenger of Allah said: The words: SubhanAllah (Glory be to Allah), Alhamdulillah (All praise is due to Allah), La ilaha illallah (There is no god but Allah), Allahu Akbar (Allah is the Greatest), (above words) are more beloved to me than everything over which the sun rises.'),
  ('dhikr_032', 'Dhikr 5 - One in Distress', 'لَا اِلٰهَ اِلَّاۤ اَنْتَ سُبْحَانَكَ اِنِّىْ كُنْتُ مِنَ الظَّالِمِيْنَ', 'Laa ilaaha illa anta subhaanaka; Innee kuntu minadh-dhaalimeen.', 'None has the right to be worshipped except you. How perfect you are, verily I was among the wrong doers.', 1, NULL, 'remembrance_of_allah', 'Ibrahim bin Muhammad bin Sa`d (RA) narrated from his father, from Sa`d that the Messenger of Allah said: The supplication of Dhun-Nun (Prophet Yunus) when he supplicated, while in the belly of the whale was: There is none worthy of worship except You, Glory to You, Indeed, I have been of the transgressors. (La ilaha illa anta subhaanaka inni kuntu minaz-zalimin). So indeed, no Muslim man supplicates with it for anything, ever, except Allah responds to him.', 'Jami at-Tirmidhi 3505', 32, 'Ibrahim bin Muhammad bin Sa`d (RA) narrated from his father, from Sa`d that the Messenger of Allah said: The supplication of Dhun-Nun (Prophet Yunus) when he supplicated, while in the belly of the whale was: There is none worthy of worship except You, Glory to You, Indeed, I have been of the transgressors. (La ilaha illa anta subhaanaka inni kuntu minaz-zalimin). So indeed, no Muslim man supplicates with it for anything, ever, except Allah responds to him.'),
  ('daily_dua_033', 'Seek Refuge', 'اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِكَ مِنْ عَذَابِ الْقَبْرِ، وَمِنْ عَذَابِ جَهَنَّمَ، وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ، وَمِنْ شَرِّ فِتْنَةِ الْمَسِيْحِ الدَّجَّالِ', 'Allahumma innee a''oodhu bika min adhaabil-qabr; Wa min adhaabi jahannam; Wa min fitnatil mahyaa wa mamaat; Wa min sharri fitnatil maseehid-dajjaal.', 'O Allah, I seek refuge in You from the punishment of the grave, and from the punishment of Hell-fire, and from the trials of life and death, and from the evil of the trial of the False Messiah.', 1, NULL, 'daily_duas', 'Narrated Abu Huraira (RA): Allah''s Messenger used to invoke (Allah): Allahumma ini a''udhu bika min ''adhabi-l-Qabr, wa min ''adhabi-nnar, wa min fitnati-l-mahya wal-mamat, wa min fitnati-l-masih ad-dajjal. O Allah! I seek refuge with you from the punishment in the grave and from the punishment in the Hell fire and from the afflictions of life and death, and the afflictions of Al-Masih Ad-Dajjal. (Sahih al-Bukhari 1377) — Abu Huraira reported: The Messenger of Allah said: When any one of you utters tashahhud (in prayer) he must seek refuge with Allah from four (trials) and should thus say: O Allah! I seek refuge with Thee from the torment of the Hell, from the torment of the grave, from the trial of life and death and from the evil of the trial of Masih al-Dajjal (Antichrist). (Sahih Muslim 588a)', 'Sahih al-Bukhari 1377 | Sahih Muslim 588a | Hisn al-Muslim 55', 33, 'Narrated Abu Huraira (RA): Allah''s Messenger used to invoke (Allah): Allahumma ini a''udhu bika min ''adhabi-l-Qabr, wa min ''adhabi-nnar, wa min fitnati-l-mahya wal-mamat, wa min fitnati-l-masih ad-dajjal. O Allah! I seek refuge with you from the punishment in the grave and from the punishment in the Hell fire and from the afflictions of life and death, and the afflictions of Al-Masih Ad-Dajjal. (Sahih al-Bukhari 1377) — Abu Huraira reported: The Messenger of Allah said: When any one of you utters tashahhud (in prayer) he must seek refuge with Allah from four (trials) and should thus say: O Allah! I seek refuge with Thee from the torment of the Hell, from the torment of the grave, from the trial of life and death and from the evil of the trial of Masih al-Dajjal (Antichrist). (Sahih Muslim 588a)'),
  ('daily_dua_034', 'Leaving all affair to Allah', 'حَسْبُنَا اللهُ وَنِعْمَ الْوَكِيْلُ', 'Hasbunallahu wa ni''mal wakeel.', 'Allah is sufficient for us and the best of those on whom to depend.', 1, NULL, 'daily_duas', 'Narrated Ibn Abbas (RA): ''Allah is Sufficient for us and He Is the Best Disposer of affairs,'' was said by Abraham (A.S) when he was thrown into the fire; and it was said by Muhammad when they (i.e. hypocrites) said, ''A great army is gathering against you, therefore, fear them,'' but it only increased their faith and they said: ''Allah is Sufficient for us, and He is the Best Disposer (of affairs, for us).'' (Sura Al-Imran 3.173)', 'Sura Al-Imran 3:173 | Sahih al-Bukhari 4563 | Hisn al-Muslim 128', 34, 'Narrated Ibn Abbas (RA): ''Allah is Sufficient for us and He Is the Best Disposer of affairs,'' was said by Abraham (A.S) when he was thrown into the fire; and it was said by Muhammad when they (i.e. hypocrites) said, ''A great army is gathering against you, therefore, fear them,'' but it only increased their faith and they said: ''Allah is Sufficient for us, and He is the Best Disposer (of affairs, for us).'' (Sura Al-Imran 3.173)'),
  ('daily_dua_035', 'The Greatest Name Of Allah', 'اَللّٰهُمَّ اِنِّيْۤ اَسْاَلُكَ بِاَنَّكَ اَنْتَ اللهُ، اَلْاَحَدُ الصَّمَدُ، الَّذِيْ لَمْ يَلِدْ وَلَمْ يُوْلَدْ، وَلَمْ يَكُنْ لَّهٗ كُفُوًا اَحَدٌ', 'Allahumma inni as''aluka bi-annaka Antallah; Al-Ahadus-Samad; Alladhi lam yalid wa lam yoolad; Wa lam yakun lahu kufuwan ahad.', 'O Allah! I ask You by virtue of Your being Allah, the One, the Self-Sufficient Master, Who begets not nor was begotten, and there is none co-equal or comparable to Him.', 1, NULL, 'daily_duas', 'It was narrated from Abdullah bin Buraidah (RA) that his father said: The Prophet heard a man say: Allahumma! Inni as''aluka bi-annaka Antallahul-Ahadus-Samad, alladhi lam yalid wa lam yuwlud, wa lam yakun lahu kufuwan ahad (O Allah! I ask You by virtue of Your being Allah, the One, the Self-Sufficient Master, Who begets not nor was begotten, and there is none co-equal or comparable to Him). The Messenger of Allah (saas) said: He has asked Allah by His Greatest Name, which if He is asked thereby He gives, and if He is called upon thereby He answers.', 'Sunan Ibn Majah', 35, 'It was narrated from Abdullah bin Buraidah (RA) that his father said: The Prophet heard a man say: Allahumma! Inni as''aluka bi-annaka Antallahul-Ahadus-Samad, alladhi lam yalid wa lam yuwlud, wa lam yakun lahu kufuwan ahad (O Allah! I ask You by virtue of Your being Allah, the One, the Self-Sufficient Master, Who begets not nor was begotten, and there is none co-equal or comparable to Him). The Messenger of Allah (saas) said: He has asked Allah by His Greatest Name, which if He is asked thereby He gives, and if He is called upon thereby He answers.'),
  ('daily_dua_036', 'When Breaking Fast', 'ذَهَبَ الظَّمَاُ، وَابْتَلَّتِ الْعُرُوْقُ، وَثَبَتَ الْاَجْرُ اِنْ شَآءَ اللهُ', 'Dhahabadh-dhama''; Wabtallatil-urooq; Wa thabatal-ajru in shaa Allah.', 'The thirst has quenched and left wetness and with the will of Allah, reward is proven (certain).', 1, NULL, 'daily_duas', 'Marwan ibn Salim al-Muqaffa (RA) said: I saw Ibn Umar holding his beard with his hand and cutting what exceeded the handful of it. He (Ibn Umar) said that the Prophet said when he broke his fast: Thirst has gone, the arteries are moist, and the reward is sure, if Allah wills.', 'Sunan Abi Dawud 2357 | Hisn al-Muslim 176', 36, 'Marwan ibn Salim al-Muqaffa (RA) said: I saw Ibn Umar holding his beard with his hand and cutting what exceeded the handful of it. He (Ibn Umar) said that the Prophet said when he broke his fast: Thirst has gone, the arteries are moist, and the reward is sure, if Allah wills.'),
  ('daily_dua_037', 'Protection from Hellfire', 'اَللّٰهُمَّ اَجِرْنِىْ مِنَ النَّارِ', 'Allahumma ajirni minan-naar. (Recite three times)', 'O Allah, save me from the fire. (Recite three times)', 3, NULL, 'daily_duas', 'It was narrated that Anas bin Malik (RA) said: The Messenger of Allah said: Whoever asks Allah for Paradise three times, Paradise will say: O Allah, admit him to Paradise. And whoever seeks protection from Hell three times, Hell will say: O Allah, protect him from the Fire.', 'Sunan an-Nasa''i 5521', 37, 'It was narrated that Anas bin Malik (RA) said: The Messenger of Allah said: Whoever asks Allah for Paradise three times, Paradise will say: O Allah, admit him to Paradise. And whoever seeks protection from Hell three times, Hell will say: O Allah, protect him from the Fire.'),
  ('daily_dua_038', 'Fear of Shirk', 'اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِكَ اَنْ اُّشْرِكَ بِكَ وَاَنَا اَعْلَمُ، وَاَسْتَغْفِرُكَ لِمَا لَاۤ اَعْلَمُ', 'Allahumma innee a''oodhu bika an ushrika bika wa-ana a''lam; Wa astaghfiruka limaa laa a''lam.', 'O Allah, I seek refuge in You lest I associate anything with You knowingly, and I seek Your forgiveness for what I know not.', 1, NULL, 'daily_duas', 'Maqil bin Yasar (RA) said that he came to the Prophet with Abu Bakr (RA). He said, O Abu Bakr, polytheism enters your people more quietly (secretly) than the movement of ants. Abu Bakr (RA) asked, Is there a kind of polytheism besides associating anything with Allah? The Prophet said, By him who has my life in his power, polytheism is more concealed than the movement of ants. Shall I not teach you something which if you say will eliminate minor or major (polytheism)? He then said, Say O Allah! I seek refuge in you lest I associate anything with you while I know it, and I seek your forgiveness for what I do not know.', 'Al-Adab Al-Mufrad 716 | Hisn al-Muslim 203', 38, 'Maqil bin Yasar (RA) said that he came to the Prophet with Abu Bakr (RA). He said, O Abu Bakr, polytheism enters your people more quietly (secretly) than the movement of ants. Abu Bakr (RA) asked, Is there a kind of polytheism besides associating anything with Allah? The Prophet said, By him who has my life in his power, polytheism is more concealed than the movement of ants. Shall I not teach you something which if you say will eliminate minor or major (polytheism)? He then said, Say O Allah! I seek refuge in you lest I associate anything with you while I know it, and I seek your forgiveness for what I do not know.'),
  ('daily_dua_039', 'Any Difficult Affairs', 'اَللّٰهُمَّ لَا سَهْلَ اِلَّا مَا جَعَلْتَهٗ سَهْلًا، وَاَنْتَ تَجْعَلُ الْحَزْنَ اِذَا شِئْتَ سَهْلًا', 'Allahumma la sahla illaa maa ja''altahu sahlaa; Wa anta taj''alul-hazna idhaa shi''ta sahlaa.', 'O Allah, there is no ease except in that which You have made easy, and You make the difficulty, if You wish, easy.', 1, NULL, 'daily_duas', 'Narrated Anas bin Maalik (RA) that the Prophet said in another narration: the Prophet used to supplicate saying: Allahumma la sahla illa ma ja`altahu sahla wa anta taj`al ul-hazna idha shi''ta sahla. (Shaykh Al-Albani declared it Sahih in al-Saheehah 2886 and said: It is as per the condition of Imam Muslim. And also graded as Sahih by Shaikh Muqbil in Sahih al-Musnad 73.)', 'Silsilah al-Saheehah 2886 | Sahih Ibn Hibban 2427 | Hisn al-Muslim 139', 39, 'Narrated Anas bin Maalik (RA) that the Prophet said in another narration: the Prophet used to supplicate saying: Allahumma la sahla illa ma ja`altahu sahla wa anta taj`al ul-hazna idha shi''ta sahla. (Shaykh Al-Albani declared it Sahih in al-Saheehah 2886 and said: It is as per the condition of Imam Muslim. And also graded as Sahih by Shaikh Muqbil in Sahih al-Musnad 73.)'),
  ('daily_dua_040', 'Anxiety and Sorrow', 'اَللّٰهُمَّ اِنِّيْۤ اَعُوْذُ بِكَ مِنَ الْهَمِّ وَالْحَزَنِ، وَالْعَجْزِ وَالْكَسَلِ، وَالْبُخْلِ وَالْجُبْنِ، وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ', 'Allahumma innee a''oodhu bika minal-hammi wal-hazan; Wal-''ajzi wal-kasal; Wal-bukhli wal-jubn; Wa dhala''id-dayni wa ghalabatir-rijaal.', 'O Allah! I seek refuge with You from worry and grief, from incapacity and laziness, from cowardice and miserliness, from being heavily in debt and from being overpowered by (other) men.', 1, NULL, 'daily_duas', 'Narrated Anas bin Malik: The Prophet used to say, O Allah! I seek refuge with You from worry and grief, from incapacity and laziness, from cowardice and miserliness, from being heavily in debt and from being overpowered by (other) men.', 'Sahih al-Bukhari 6369 | Hisn al-Muslim 137', 40, 'Narrated Anas bin Malik: The Prophet used to say, O Allah! I seek refuge with You from worry and grief, from incapacity and laziness, from cowardice and miserliness, from being heavily in debt and from being overpowered by (other) men.'),
  ('daily_dua_041', 'Having Relation with Wife', 'بِسْمِ اللهِ، اَللّٰهُمَّ جَنِّبْنَا الشَّيْطَانَ، وَجَنِّبِ الشَّيْطَانَ مَا رَزَقْتَنَا', 'Bismillah; Allahumma jannibna ash-shaytaan; Wa jannibi ash-shaytaana maa razaqtanaa.', 'In the Name of Allah, O Allah! Keep us away from Satan and keep Satan away from what You have bestowed upon us. And if Allah has ordained a child for them, Satan will never harm him.', 1, NULL, 'daily_duas', 'Narrated Ibn Abbas (RA): The Prophet said, If anyone of you, when intending to have a sexual intercourse with his wife, says: Bismillah, Allahumma jannibna-sh-shaitan, wa jannibi-sh-shaitan ma razaqtana, and if the couple are destined to have a child (out of that very sexual intercourse), then Satan will never be able to harm that child.', 'Sahih al-Bukhari', 41, 'Narrated Ibn Abbas (RA): The Prophet said, If anyone of you, when intending to have a sexual intercourse with his wife, says: Bismillah, Allahumma jannibna-sh-shaitan, wa jannibi-sh-shaitan ma razaqtana, and if the couple are destined to have a child (out of that very sexual intercourse), then Satan will never be able to harm that child.'),
  ('daily_dua_042', 'Entering the Market', 'لَا اِلٰهَ اِلَّا اللهُ وَحْدَهٗ لَا شَرِيْكَ لَهٗ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، يُحْيِىْ وَيُمِيْتُ، وَهُوَ حَيٌّ لَّا يَمُوْتُ، بِيَدِهِ الْخَيْرُ، وَهُوَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ', 'La ilaha illallah, wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, yuhyi wa yumitu, wa huwa hayyun la yamootu, biyadihil-khairu, wa huwa ''ala kulli shay''in qadir.', 'INCOMPLETE - top section scrolled. Visible end: ...death, He is Living and does not die, in His Hand is the good, and He has power over all things. Whoever says it on entering the market, Allah shall record a million good deeds for him, wipe a million evil deeds away from him, and raise a million ranks for him.', 1, NULL, 'daily_duas', 'Note (visible bottom only — top scrolled off): Allah shall record a million good deeds for him, wipe a million evil deeds away from him, and raise a million ranks for him. Classed as Hasan by Shaykh al-Albani in Silsilat al-Ahadith as-Sahihah no. 3139.', 'Jami at-Tirmidhi 3428 | Hisn al-Muslim 209 | Silsilat al-Ahadith as-Sahihah 3139', 42, 'Note (visible bottom only — top scrolled off): Allah shall record a million good deeds for him, wipe a million evil deeds away from him, and raise a million ranks for him. Classed as Hasan by Shaykh al-Albani in Silsilat al-Ahadith as-Sahihah no. 3139.'),
  ('daily_dua_043', 'When Visiting Sick', 'لَا بَاْسَ طَهُوْرٌ اِنْ شَآءَ اللهُ', 'Laa ba''sa tahoorun, in shaa Allah.', 'Do not worry, it will be a purification (for you) Allah willing.', 1, NULL, 'daily_duas', 'Narrated Ibn Abbas (RA): The Prophet went to visit a sick bedouin. Whenever the Prophet went to a patient, he used to say to him, Don''t worry, if Allah will, it will be expiation (for your sins). The bedouin said, You say expiation? No, it is but a fever that is boiling or harassing an old man and will lead him to his grave without his will. The Prophet said, Then, yes, it is so.', 'Sahih al-Bukhari', 43, 'Narrated Ibn Abbas (RA): The Prophet went to visit a sick bedouin. Whenever the Prophet went to a patient, he used to say to him, Don''t worry, if Allah will, it will be expiation (for your sins). The bedouin said, You say expiation? No, it is but a fever that is boiling or harassing an old man and will lead him to his grave without his will. The Prophet said, Then, yes, it is so.'),
  ('rabbana_001', 'Rabanna Quranic Dua 1', 'رَبَّنَا تَقَبَّلْ مِنَّاۤ اِنَّكَ اَنْتَ السَّمِيْعُ الْعَلِيْمُ', 'Rabbana taqabbal minnaa; Innaka Antas-Samee''ul-''Aleem.', 'Our Lord, accept [this] from us. Indeed You are the Hearing, the Knowing. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. You can recite this du''a whenever you would like for Allah to accept whatever good you''ve just done. Du''a Prophet Ibrahim recited after building the Kaaba with his son.', 'Surah Al-Baqara 2:127', 1, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. You can recite this du''a whenever you would like for Allah to accept whatever good you''ve just done. Du''a Prophet Ibrahim recited after building the Kaaba with his son.'),
  ('rabbana_002', 'Rabanna Quranic Dua 2', 'رَبَّنَا وَاجْعَلْنَا مُسْلِمَيْنِ لَكَ وَمِنْ ذُرِّيَّتِنَاۤ اُمَّةً مُّسْلِمَةً لَّكَ وَاَرِنَا مَنَاسِكَنَا وَتُبْ عَلَيْنَاۤ اِنَّكَ اَنْتَ التَّوَّابُ الرَّحِيْمُ', 'Rabbana waj''alna Mus''limayni Laka; Wa min dhurriyyatina ummatan Mus''limatal-Laka; Wa arinaa manaasikana; Wa tub ''alaynaa; Innaka Antat-Tawwaabur-Raheem.', 'Our Lord, and make us Muslims [in submission] to You and from our descendants a Muslim nation [in submission] to You. And show us our rites and accept our repentance. Indeed, You are the Accepting of repentance, the Merciful. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This du''a should be recited to affirm your faith in Islam. It also a good prayer that asks for the success of the entire Muslim Ummah. Du''a Prophet Ibrahim recited after building the Kaaba with his son.', 'Surah Al-Baqara 2:128', 2, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This du''a should be recited to affirm your faith in Islam. It also a good prayer that asks for the success of the entire Muslim Ummah. Du''a Prophet Ibrahim recited after building the Kaaba with his son.'),
  ('rabbana_003', 'Rabanna Quranic Dua 3', 'رَبَّنَاۤ اٰتِنَا فِى الدُّنْيَا حَسَنَةً وَّفِى الْاٰخِرَةِ حَسَنَةً وَّقِنَا عَذَابَ النَّارِ', 'Rabbana aatina fid-dunya hasanah; Wa fil-akhirati hasanah; Waqina ''adhaaban-Naar.', 'Our Lord, give us in this world [that which is] good and in the Hereafter [that which is] good and protect us from the punishment of the Fire. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. One of the best duas any believer can recite. It asks for good in this world while not forgetting to ask about good in the akhira (afterlife). So remember Me; I will remember you. And be grateful to Me and do not deny Me. (2:152)', 'Surah Al-Baqara 2:201', 3, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. One of the best duas any believer can recite. It asks for good in this world while not forgetting to ask about good in the akhira (afterlife). So remember Me; I will remember you. And be grateful to Me and do not deny Me. (2:152)'),
  ('rabbana_004', 'Rabanna Quranic Dua 4', 'رَبَّنَاۤ اَفْرِغْ عَلَيْنَا صَبْرًا وَّثَبِّتْ اَقْدَامَنَا وَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِيْنَ', 'Rabbana afrigh ''alayna sabran; Wa thabbit aqdaamanaa; Wansurna ''alal-qawmil-kaafireen.', 'Our Lord, pour upon us patience and plant firmly our feet and give us victory over the disbelieving people. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Asking Allah for protection, patience in whatever endeavor, and to be victorious. Prophetic du''a for protection recited by Prophet Dawud. Dawud was a smaller, younger man and on paper it did not seem like he was favored to win a battle against Jalut (Goliath). But we''re told, and Allah granted him dominion and wisdom, and imparted to him the knowledge of whatever He willed. (2:251)', 'Surah Al-Baqara 2:250', 4, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Asking Allah for protection, patience in whatever endeavor, and to be victorious. Prophetic du''a for protection recited by Prophet Dawud. Dawud was a smaller, younger man and on paper it did not seem like he was favored to win a battle against Jalut (Goliath). But we''re told, and Allah granted him dominion and wisdom, and imparted to him the knowledge of whatever He willed. (2:251)'),
  ('rabbana_005', 'Rabanna Quranic Dua 5', 'رَبَّنَا لَا تُؤَاخِذْنَاۤ اِنْ نَّسِيْنَاۤ اَوْ اَخْطَاْنَا', 'Rabbana laa tu''aakhidhnaaa in-naseenaa aw akhta''naa.', 'Our Lord, do not impose blame upon us if we have forgotten or erred. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a for tawbah (repentance). Asking for the forgiveness of Allah is the best kind of du''a a believer can make. It shows humility in your character, protects you from boasting or growing prideful. Constant repentance is a characteristic that shows your complete reliance on Allah for all things.', 'Surah Al-Baqara 2:286', 5, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a for tawbah (repentance). Asking for the forgiveness of Allah is the best kind of du''a a believer can make. It shows humility in your character, protects you from boasting or growing prideful. Constant repentance is a characteristic that shows your complete reliance on Allah for all things.'),
  ('rabbana_006', 'Rabanna Quranic Dua 6', 'رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَاۤ اِصْرًا كَمَا حَمَلْتَهٗ عَلَى الَّذِيْنَ مِنْ قَبْلِنَا', 'Rabbana wa laa tahmil ''alaynaa isran; Kamaa hamaltahu ''alal-ladheena min qablinaa.', 'Our Lord, and lay not upon us a burden like that which You laid upon those before us. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a asking Allah to make the path of righteousness easy upon the believers. Asking Allah for our life''s tests to be ones that we are capable of enduring and overcoming. To not be tested more severely than our predecessors.', 'Surah Al-Baqara 2:286', 6, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a asking Allah to make the path of righteousness easy upon the believers. Asking Allah for our life''s tests to be ones that we are capable of enduring and overcoming. To not be tested more severely than our predecessors.'),
  ('rabbana_007', 'Rabanna Quranic Dua 7', 'رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهٖ، وَاعْفُ عَنَّا، وَاغْفِرْ لَنَا، وَارْحَمْنَاۤ اَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِيْنَ', 'Rabbana wa laa tuhammilnaa maa laa taaqata lanaa bih; Wa''fu ''annaa; Waghfir lanaa; Warhamnaa; Anta Mawlaanaa fansurnaa ''alal-qawmil-kaafireen.', 'Our Lord, and burden us not with that which we have no ability to bear. And pardon us; and forgive us; and have mercy upon us. You are our protector, so give us victory over the disbelieving people. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. The last ayat of Surah Baqarah alone contains 3 powerful duas which can be recited together or independently. These last 2 ayat are among the most memorized verses of the Qur''an. The Messenger of Allah said: If anyone recited two verses from the last of Surah Baqarah at night, they will be sufficient for him.', 'Surah Al-Baqara 2:286', 7, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. The last ayat of Surah Baqarah alone contains 3 powerful duas which can be recited together or independently. These last 2 ayat are among the most memorized verses of the Qur''an. The Messenger of Allah said: If anyone recited two verses from the last of Surah Baqarah at night, they will be sufficient for him.'),
  ('rabbana_008', 'Rabanna Quranic Dua 8', 'رَبَّنَا لَا تُزِغْ قُلُوْبَنَا بَعْدَ اِذْ هَدَيْتَنَا وَهَبْ لَنَا مِنْ لَّدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهَّابُ', 'Rabbana laa tuzigh quloobanaa; Ba''da idh-hadaytanaa; Wa hab lanaa milladunka rahmah; Innaka Antal-Wahhaab.', 'Our Lord, let not our hearts deviate after You have guided us and grant us from Yourself mercy. Indeed, You are the Bestower. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Another beautiful du''a a believer can recite asking for Allah''s rahma (mercy). The believer understands that all things are made possible through Allah. In this du''a, we ask of Allah to make us among those who are guided, to not let the environment or circumstance change us.', 'Surah Al-Imran 3:8', 8, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Another beautiful du''a a believer can recite asking for Allah''s rahma (mercy). The believer understands that all things are made possible through Allah. In this du''a, we ask of Allah to make us among those who are guided, to not let the environment or circumstance change us.'),
  ('rabbana_009', 'Rabanna Quranic Dua 9', 'رَبَّنَاۤ اِنَّكَ جَامِعُ النَّاسِ لِيَوْمٍ لَّا رَيْبَ فِيْهِ اِنَّ اللهَ لَا يُخْلِفُ الْمِيْعَادَ', 'Rabbana innaka jaami''un-naasi li-yawmil laa rayba feeh; Innal-Laaha laa yukhliful-mee''aad.', 'Our Lord, surely You will gather the people for a Day about which there is no doubt. Indeed, Allah does not fail in His promise. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a of the believers to affirm their faith in the afterlife. A place where we will either reap the rewards for our good deeds and our actions or pay the price of errors. Indeed, Allah does not fail in his promise.', 'Surah Al-Imran 3:9', 9, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a du''a of the believers to affirm their faith in the afterlife. A place where we will either reap the rewards for our good deeds and our actions or pay the price of errors. Indeed, Allah does not fail in his promise.'),
  ('rabbana_010', 'Rabanna Quranic Dua 10', 'رَبَّنَاۤ اِنَّنَاۤ اٰمَنَّا فَاغْفِرْ لَنَا ذُنُوْبَنَا وَقِنَا عَذَابَ النَّارِ', 'Rabbana innanaa aamannaa; Faghfir lanaa dhunoobanaa; Waqinaa ''adhaaban-Naar.', 'Our Lord, indeed we have believed, so forgive us our sins and protect us from the punishment of the Fire. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance and protection. We ask Allah for forgiveness and to shield us from the punishment of the hellfire. [Remember] when you were asking help of your Lord, and He answered you, ''Indeed, I will reinforce you with a thousand from the angels, following one another.'' (8:9)', 'Surah Al-Imran 3:16', 10, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance and protection. We ask Allah for forgiveness and to shield us from the punishment of the hellfire. [Remember] when you were asking help of your Lord, and He answered you, ''Indeed, I will reinforce you with a thousand from the angels, following one another.'' (8:9)'),
  ('rabbana_011', 'Rabanna Quranic Dua 11', 'رَبَّنَاۤ اٰمَنَّا بِمَاۤ اَنْزَلْتَ وَاتَّبَعْنَا الرَّسُوْلَ فَاكْتُبْنَا مَعَ الشَّاهِدِيْنَ', 'Rabbanaa aamannaa bimaa anzalta; Wattaba''nar-Rusoola; Fak''tubnaa ma''ash-shaahideen.', 'Lord, we believe in what You have revealed and we follow the messenger: record us among those who bear witness [to the Truth]. (Translation: Abdul Haleem)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of faith and worship, i.e. to register us among the witnesses to the truth. In the Qur''an we''re told of how Allah saved Isa from the children of Israel who plotted against him: [Mention] when Allah said, Jesus, indeed I will take you...', 'Surah Al-Imran 3:53', 11, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of faith and worship, i.e. to register us among the witnesses to the truth. In the Qur''an we''re told of how Allah saved Isa from the children of Israel who plotted against him: [Mention] when Allah said, Jesus, indeed I will take you...'),
  ('rabbana_012', 'Rabanna Quranic Dua 12', 'رَبَّنَا اغْفِرْ لَنَا ذُنُوْبَنَا وَاِسْرَافَنَا فِىْۤ اَمْرِنَا وَثَبِّتْ اَقْدَامَنَا وَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِيْنَ', 'Rabbanaa-ghfir lanaa dhunoobanaa; Wa is''raafanaa fee amrinaa; Wa thabbit aqdaamanaa; Wansurnaa ''alal-qawmil-kaafireen.', 'Our Lord, forgive us our sins and the excess [committed] in our affairs and plant firmly our feet and give us victory over the disbelieving people. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a for repentance, victory, and resiliency. To plant one''s feet firmly in the face of evil. In the following verse it says, ''So Allah gave them the reward of this world and the good reward of the Hereafter. And Allah loves the doers of good.''', 'Surah Al-Imran 3:147', 12, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a for repentance, victory, and resiliency. To plant one''s feet firmly in the face of evil. In the following verse it says, ''So Allah gave them the reward of this world and the good reward of the Hereafter. And Allah loves the doers of good.'''),
  ('rabbana_013', 'Rabanna Quranic Dua 13', 'رَبَّنَا مَا خَلَقْتَ هٰذَا بَاطِلًا سُبْحَانَكَ فَقِنَا عَذَابَ النَّارِ', 'Rabbanaa maa khalaqta haadhaa baa''tilan; Subhaanaka faqinaa ''adhaaban-naar.', 'Our Lord, You did not create this aimlessly; exalted are You [above such a thing]; then protect us from the punishment of the Fire. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a praising Allah and asking for His protection from Jahannam (Hellfire). If we take the time to look at the world, we see how complex yet organized all of Allah''s creations are. We can see nothing was created aimlessly. There''s a greater purpose in everyone one of his creations. This supplication is one of gratitude, shows your appreciation for the beauty in life. The du''a continues to ask Allah for protection on the day of judgment and that we be saved from the punishment of the fire.', 'Surah Al-Imran 3:191', 13, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a praising Allah and asking for His protection from Jahannam (Hellfire). If we take the time to look at the world, we see how complex yet organized all of Allah''s creations are. We can see nothing was created aimlessly. There''s a greater purpose in everyone one of his creations. This supplication is one of gratitude, shows your appreciation for the beauty in life. The du''a continues to ask Allah for protection on the day of judgment and that we be saved from the punishment of the fire.'),
  ('rabbana_014', 'Rabanna Quranic Dua 14', 'رَبَّنَاۤ اِنَّكَ مَنْ تُدْخِلِ النَّارَ فَقَدْ اَخْزَيْتَهٗ وَمَا لِلظَّالِمِيْنَ مِنْ اَنْصَارٍ', 'Rabbanaa innaka man tud''khilin-naara faqad akhzaytah; Wa maa lidh-dhaalimeena min ansaar.', 'Our Lord, indeed whoever You admit to the Fire - You have disgraced him, and for the wrongdoers there are no helpers. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We may not think a whole lot about where we originally came from but, at some point, we''ll begin to think about where we are headed. We''ll start to ponder the consequences of our actions. It''s an important study — the relationship between cause and effect. This supplication can be used as motivation to remind yourself of where you''re going because you know the fate of the wrongdoers.', 'Surah Al-Imran 3:192', 14, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We may not think a whole lot about where we originally came from but, at some point, we''ll begin to think about where we are headed. We''ll start to ponder the consequences of our actions. It''s an important study — the relationship between cause and effect. This supplication can be used as motivation to remind yourself of where you''re going because you know the fate of the wrongdoers.'),
  ('rabbana_015', 'Rabanna Quranic Dua 15', 'رَبَّنَاۤ اِنَّنَا سَمِعْنَا مُنَادِيًا يُّنَادِيْ لِلْاِيْمَانِ اَنْ اٰمِنُوْا بِرَبِّكُمْ فَاٰمَنَّا', 'Rabbanaa innaa sami''naa munaadiyan yunaadee lil-eemaani an aaminoo bi Rabbikum; Fa aamannaa.', 'Our Lord, indeed we have heard a caller calling to faith, [saying], ''Believe in your Lord,'' and we have believed. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of humility, submission and faith. We have heard a caller (referring to Prophet Muhammad) and we have listened to his message and we believe.', 'Surah Al-Imran 3:193', 15, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of humility, submission and faith. We have heard a caller (referring to Prophet Muhammad) and we have listened to his message and we believe.'),
  ('rabbana_016', 'Rabanna Quranic Dua 16', 'رَبَّنَا فَاغْفِرْ لَنَا ذُنُوْبَنَا وَكَفِّرْ عَنَّا سَيِّاٰتِنَا وَتَوَفَّنَا مَعَ الْاَبْرَارِ', 'Rabbanaa fagh''fir lanaa dhunoobanaa; Wa kaffir ''annaa sayyi''aatinaa; Wa tawaffanaa ma''al-abraar.', 'Our Lord, so forgive us our sins and remove from us our misdeeds and cause us to die with the righteous. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance, washing away our misdeeds, and asking Allah to cause us to die guided on the right path. Narrated Ibn Abbas: (One night) I stayed overnight in the house of my aunt Maimuna, and said to myself, ''I will watch the prayer of Allah''s Messenger.'' My aunt placed a cushion for Allah''s Messenger and he slept on it in its length-wise direction and (woke-up) rubbing the traces of sleep off his face and then he recited the last ten Verses of Surah Imran till he finished it.', 'Surah Al-Imran 3:193', 16, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance, washing away our misdeeds, and asking Allah to cause us to die guided on the right path. Narrated Ibn Abbas: (One night) I stayed overnight in the house of my aunt Maimuna, and said to myself, ''I will watch the prayer of Allah''s Messenger.'' My aunt placed a cushion for Allah''s Messenger and he slept on it in its length-wise direction and (woke-up) rubbing the traces of sleep off his face and then he recited the last ten Verses of Surah Imran till he finished it.'),
  ('rabbana_017', 'Rabanna Quranic Dua 17', 'رَبَّنَا وَاٰتِنَا مَا وَعَدْتَّنَا عَلٰى رُسُلِكَ وَلَا تُخْزِنَا يَوْمَ الْقِيٰمَةِ اِنَّكَ لَا تُخْلِفُ الْمِيْعَادَ', 'Rabbanaa wa aatinaa maa wa''adtanaa ''ala rusulika; Wa laa tukh''zinaa yawmal-Qiyaamah; Innaka laa tukhliful mee''aad.', 'Our Lord, and grant us what You promised us through Your messengers and do not disgrace us on the Day of Resurrection. Indeed, You do not fail in [Your] promise. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of humility, to be saved from being disgraced on the day of judgment. To a true believer, there is no doubt that Allah will indeed fulfill his promise. Rather this is a prayer to Allah asking to be worthy of his promise.', 'Surah Al-Imran 3:194', 17, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of humility, to be saved from being disgraced on the day of judgment. To a true believer, there is no doubt that Allah will indeed fulfill his promise. Rather this is a prayer to Allah asking to be worthy of his promise.'),
  ('rabbana_018', 'Rabanna Quranic Dua 18', 'رَبَّنَاۤ اٰمَنَّا فَاكْتُبْنَا مَعَ الشَّاهِدِيْنَ', 'Rabbanaa aamannaa fak''tubnaa ma''ash-shaahideen.', 'Our Lord, we have believed, so register us among the witnesses. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for those who want to testify the truth and verbally affirm their belief in it. Any who is (so) grateful does so to the profit of his own soul: but if any is ungrateful, verily Allah is free of all wants, Worthy of all praise.', 'Surah Al-Ma''idah 5:83', 18, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for those who want to testify the truth and verbally affirm their belief in it. Any who is (so) grateful does so to the profit of his own soul: but if any is ungrateful, verily Allah is free of all wants, Worthy of all praise.'),
  ('rabbana_019', 'Rabanna Quranic Dua 19', 'رَبَّنَاۤ اَنْزِلْ عَلَيْنَا مَآئِدَةً مِّنَ السَّمَآءِ تَكُوْنُ لَنَا عِيْدًا لِّاَوَّلِنَا وَاٰخِرِنَا وَاٰيَةً مِّنْكَ وَارْزُقْنَا وَاَنْتَ خَيْرُ الرَّازِقِيْنَ', 'Rabbanaa anzil ''alaina maa''idatam minas-samaa''i; Takoonu lanaa ''eedal li-awwalinaa wa aakhirinaa wa aayatam minka; War''zuqnaa wa anta khayrur-raaziqeen.', 'O Allah, our Lord, send down to us a table [spread with food] from the heaven to be for us a festival for the first of us and the last of us and a sign from You. And provide for us, and You are the best of providers. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for provision. Provision is all encompassing term meaning to supply with food, money, or way to make a living. All good provisions come from Allah, we turn to him and ask him to provide for us. This is a du''a Isa (Jesus) alayhis salaam recited asking for sufficient food for him and his followers. Allah replies in the following verse, I am going to send it down to you; but whoever from you disbelieves...', 'Surah Al-Ma''idah 5:114', 19, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for provision. Provision is all encompassing term meaning to supply with food, money, or way to make a living. All good provisions come from Allah, we turn to him and ask him to provide for us. This is a du''a Isa (Jesus) alayhis salaam recited asking for sufficient food for him and his followers. Allah replies in the following verse, I am going to send it down to you; but whoever from you disbelieves...'),
  ('rabbana_020', 'Rabanna Quranic Dua 20', 'رَبَّنَا ظَلَمْنَاۤ اَنْفُسَنَا وَاِنْ لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُوْنَنَّ مِنَ الْخٰسِرِيْنَ', 'Rabbanaa dhalamnaa anfusanaa; Wa illam tagh''fir lanaa wa tarhamnaa; Lanakoonanna minal-khaasireen.', 'Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance (tawbah). We can learn from how Adam responded after he erred. Being able to admit your faults and to harbor guilt is a beautiful sign of our belief and dedication to Allah subhanahu wa ta''ala. We ask for his forgiveness and avoid repeating the same mistakes. This is the du''a Prophet Adam recited after sinning in paradise.', 'Surah Al-A''raf 7:23', 20, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a for repentance (tawbah). We can learn from how Adam responded after he erred. Being able to admit your faults and to harbor guilt is a beautiful sign of our belief and dedication to Allah subhanahu wa ta''ala. We ask for his forgiveness and avoid repeating the same mistakes. This is the du''a Prophet Adam recited after sinning in paradise.'),
  ('rabbana_021', 'Rabanna Quranic Dua 21', 'رَبَّنَا لَا تَجْعَلْنَا مَعَ الْقَوْمِ الظَّالِمِيْنَ', 'Rabbanaa laa taj''alnaa ma''al-qawmidh-dhaalimeen.', 'Our Lord, do not place us with the wrongdoing people. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We should know that we are the sum total of the people we associate with. Intellectually we may know that the fate of the wrongdoing people will not be pleasant one but, in our day-to-day life, we may be blind to this reality because it takes place inch by inch. Only when the end is shown do we realize the mistake in our judgment. Unfortunately, it''s too late by then. This du''a asks Allah to protect us from being a victim to that fate.', 'Surah Al-A''raf 7:47', 21, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We should know that we are the sum total of the people we associate with. Intellectually we may know that the fate of the wrongdoing people will not be pleasant one but, in our day-to-day life, we may be blind to this reality because it takes place inch by inch. Only when the end is shown do we realize the mistake in our judgment. Unfortunately, it''s too late by then. This du''a asks Allah to protect us from being a victim to that fate.'),
  ('rabbana_022', 'Rabanna Quranic Dua 22', 'رَبَّنَا افْتَحْ بَيْنَنَا وَبَيْنَ قَوْمِنَا بِالْحَقِّ وَاَنْتَ خَيْرُ الْفَاتِحِيْنَ', 'Rabbanaf''tah baynanaa wa bayna qawminaa bil-haqqi; Wa anta khayrul-faatiheen.', 'Our Lord, decide between us and our people in truth, and You are the best of those who give decision. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Suhaib. Prophet Suhaib recited this du''a after facing heavy opposition from the eminent people of the city. They threatened to evict him from the city unless he fabricated a lie against Allah. His reply: ''We would have invented against Allah a lie if we returned to your religion after Allah had saved us from it. And it is not for us to return to it except that Allah, our Lord, should will. Our Lord has encompassed all things in knowledge.'' He then recited the Rabbana du''a above.', 'Surah Al-A''raf 7:89', 22, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Suhaib. Prophet Suhaib recited this du''a after facing heavy opposition from the eminent people of the city. They threatened to evict him from the city unless he fabricated a lie against Allah. His reply: ''We would have invented against Allah a lie if we returned to your religion after Allah had saved us from it. And it is not for us to return to it except that Allah, our Lord, should will. Our Lord has encompassed all things in knowledge.'' He then recited the Rabbana du''a above.'),
  ('rabbana_023', 'Rabanna Quranic Dua 23', 'رَبَّنَاۤ اَفْرِغْ عَلَيْنَا صَبْرًا وَّتَوَفَّنَا مُسْلِمِيْنَ', 'Rabbanaa afrigh ''alaynaa sabran; Wa tawaffanaa Muslimeen.', 'Our Lord, pour upon us patience and let us die as Muslims [in submission to You]. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Musa. Du''a for sabr (patience), perseverance, and a prayer requesting Allah to let us die righteously. This was recited after Firawn resorted to persecution and threatened Musa after he threw his staff and established the truth among all those who disbelieved.', 'Surah Al-A''raf 7:126', 23, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Musa. Du''a for sabr (patience), perseverance, and a prayer requesting Allah to let us die righteously. This was recited after Firawn resorted to persecution and threatened Musa after he threw his staff and established the truth among all those who disbelieved.'),
  ('rabbana_024', 'Rabanna Quranic Dua 24', 'رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِّلْقَوْمِ الظَّالِمِيْنَ، وَنَجِّنَا بِرَحْمَتِكَ مِنَ الْقَوْمِ الْكَافِرِيْنَ', 'Rabbanaa laa taj''alnaa fitnatan lil-qawmidh-dhaalimeen; Wa najjinaa bi-rahmatika minal-qawmil-kaafireen.', 'Our Lord, make us not [objects of] trial for the wrongdoing people. And save us by Your mercy from the disbelieving people. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a prayer the companions of Musa recited asking for protection from evil and unjust people. It is a du''a for success and protection. It asks to not be made examples of by disbelieving people. They faced real persecution from the tyrannical Firawn and wanted to be a source of goodness in the world.', 'Surah Yunus 10:85-86', 24, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. This is a prayer the companions of Musa recited asking for protection from evil and unjust people. It is a du''a for success and protection. It asks to not be made examples of by disbelieving people. They faced real persecution from the tyrannical Firawn and wanted to be a source of goodness in the world.'),
  ('rabbana_025', 'Rabanna Quranic Dua 25', 'رَبَّنَاۤ اِنَّكَ تَعْلَمُ مَا نُخْفِىْ وَمَا نُعْلِنُ، وَمَا يَخْفٰى عَلَى اللهِ مِنْ شَىْءٍ فِى الْاَرْضِ وَلَا فِى السَّمَآءِ', 'Rabbanaa innaka ta''lamu maa nukhfee wa maa nu''lin; Wa maa yakhfaa ''alal-laahi min shay''in fil-ardi wa laa fis-samaa''.', 'Our Lord, indeed You know what we conceal and what we declare, and nothing is hidden from Allah on the earth or in the heaven. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a showing complete trust and reliance on Allah. This du''a is a reminder that Allah is all knowing and all powerful. That nothing can be hidden from Allah. He knows the intent behind our actions, whether they be sincere or disingenuous.', 'Surah Ibrahim 14:38', 25, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a showing complete trust and reliance on Allah. This du''a is a reminder that Allah is all knowing and all powerful. That nothing can be hidden from Allah. He knows the intent behind our actions, whether they be sincere or disingenuous.'),
  ('rabbana_026', 'Rabanna Quranic Dua 26', 'رَبَّنَا وَتَقَبَّلْ دُعَآءِ', 'Rabbanaa wa taqabbal du''aa''.', 'Our Lord, and accept my supplication. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim. Prophet Ibrahim knows of the past communities and how they have erred. So, in this du''a, he asks Allah to make ourselves and the future generations good Muslims. More specifically, those who fulfill their second obligation of offering their daily prayer. The du''a concludes by asking Allah to hear and accept our supplication.', 'Surah Ibrahim 14:40', 26, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim. Prophet Ibrahim knows of the past communities and how they have erred. So, in this du''a, he asks Allah to make ourselves and the future generations good Muslims. More specifically, those who fulfill their second obligation of offering their daily prayer. The du''a concludes by asking Allah to hear and accept our supplication.'),
  ('rabbana_027', 'Rabanna Quranic Dua 27', 'رَبَّنَا اغْفِرْ لِيْ وَلِوَالِدَىَّ وَلِلْمُؤْمِنِيْنَ يَوْمَ يَقُوْمُ الْحِسَابُ', 'Rabbanaa-ghfir lee wa li-waalidayya; Wa lil-mu''mineena yawma yaqoomul-hisaab.', 'Our Lord, forgive me and my parents and the believers the Day the account is established. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim. Recommended use: Du''a asking Allah to forgive yourself and to forgive your parents. Abu Hurairah (ra) said, ''The dead person can be raised a degree after his death. He said, My Lord, how is this? He was told, Your child can ask for forgiveness for you.''', 'Surah Ibrahim 14:41', 27, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim. Recommended use: Du''a asking Allah to forgive yourself and to forgive your parents. Abu Hurairah (ra) said, ''The dead person can be raised a degree after his death. He said, My Lord, how is this? He was told, Your child can ask for forgiveness for you.'''),
  ('rabbana_028', 'Rabanna Quranic Dua 28', 'رَبَّنَاۤ اٰتِنَا مِنْ لَّدُنْكَ رَحْمَةً وَّهَيِّئْ لَنَا مِنْ اَمْرِنَا رَشَدًا', 'Rabbanaa aatinaa mil-ladunka rahmatan; Wa hayyi'' lanaa min amrinaa rashadaa.', 'Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a seeking Allah''s approval, mercy, provision, and patience. This du''a is found in Surah Kahf (titled ''the cave'') and was recited by the young men who fled their city fearing persecution for practicing their religion and found refuge in the cave. They turned to their creator asking for guidance in those tough times and their prayers were answered.', 'Surah Al-Kahf 18:10', 28, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a seeking Allah''s approval, mercy, provision, and patience. This du''a is found in Surah Kahf (titled ''the cave'') and was recited by the young men who fled their city fearing persecution for practicing their religion and found refuge in the cave. They turned to their creator asking for guidance in those tough times and their prayers were answered.'),
  ('rabbana_029', 'Rabanna Quranic Dua 29', 'رَبَّنَاۤ اِنَّنَا نَخَافُ اَنْ يَّفْرُطَ عَلَيْنَاۤ اَوْ اَنْ يَّطْغٰى', 'Rabbanaa innaa nakhaafu any-yafruta ''alaynaa; Aw any-yatghaa.', 'Our Lord, indeed we are afraid that he will hasten [punishment] against us or that he will transgress. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a both Harun and Musa recited: It can be scary to stand up for what is right, to avoid being a bystander when we see injustice happening around us. It wasn''t easy either for Harun and Musa who feared Firawn and asked Allah for his help. Allah responded in the following verse, Do not be afraid. I am surely with you both I hear and I see.', 'Surah Ta-Ha 20:45', 29, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a both Harun and Musa recited: It can be scary to stand up for what is right, to avoid being a bystander when we see injustice happening around us. It wasn''t easy either for Harun and Musa who feared Firawn and asked Allah for his help. Allah responded in the following verse, Do not be afraid. I am surely with you both I hear and I see.'),
  ('rabbana_030', 'Rabanna Quranic Dua 30', 'رَبَّنَاۤ اٰمَنَّا فَاغْفِرْ لَنَا وَارْحَمْنَا وَاَنْتَ خَيْرُ الرَّاحِمِيْنَ', 'Rabbanaa aamannaa faghfir lanaa; Warhamnaa wa anta khayrur-raahimeen.', 'Our Lord, we have believed, so forgive us and have mercy upon us, and You are the best of the merciful. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a asking for Allah''s mercy and calling upon by his rightful attribute of being Ar-Rahim meaning the most merciful. Other verses in the Qur''an claiming he is the most merciful are 7:151, 21:83, 23:118, 12:64, and 12:92.', 'Surah Al-Mu''minun 23:109', 30, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a asking for Allah''s mercy and calling upon by his rightful attribute of being Ar-Rahim meaning the most merciful. Other verses in the Qur''an claiming he is the most merciful are 7:151, 21:83, 23:118, 12:64, and 12:92.'),
  ('rabbana_031', 'Rabanna Quranic Dua 31', 'رَبَّنَا اصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ اِنَّ عَذَابَهَا كَانَ غَرَامًا، اِنَّهَا سَآءَتْ مُسْتَقَرًّا وَّمُقَامًا', 'Rabbanaa-srif ''annaa ''adhaaba jahannam; Inna ''adhaabaha kaana gharaamaa; Innahaa saa''at musta-qarraw wa muqaamaa.', 'Our Lord, avert from us the punishment of Hell. Indeed, its punishment is ever adhering; Indeed, it is evil as a settlement and residence. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a reminding us of the evil residence that is hell. It asks Allah for our protection from Jahannam.', 'Surah Al-Furqan 25:65-66', 31, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a reminding us of the evil residence that is hell. It asks Allah for our protection from Jahannam.'),
  ('rabbana_032', 'Rabanna Quranic Dua 32', 'رَبَّنَا هَبْ لَنَا مِنْ اَزْوَاجِنَا وَذُرِّيّٰتِنَا قُرَّةَ اَعْيُنٍ وَّاجْعَلْنَا لِلْمُتَّقِيْنَ اِمَامًا', 'Rabbanaa hab lanaa min azwaajinaa wa dhurriyyatinaa qurrata a''yun; Waj''alnaa lil-muttaqeena imaamaa.', 'Our Lord, grant us from among our wives and offspring comfort to our eyes and make us an example for the righteous. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. qurrata ''ayonin is an old Arabic expression meaning to bring ''coolness to the eye'' particularly from spiritual perspective to bring calmness, joy, or happiness. Asking Allah to grant us ''coolness of the eyes'' among our wives and through our children and future generations. To gift us as being a good leader, a role model for the righteous.', 'Surah Al-Furqan 25:74', 32, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. qurrata ''ayonin is an old Arabic expression meaning to bring ''coolness to the eye'' particularly from spiritual perspective to bring calmness, joy, or happiness. Asking Allah to grant us ''coolness of the eyes'' among our wives and through our children and future generations. To gift us as being a good leader, a role model for the righteous.'),
  ('rabbana_033', 'Rabanna Quranic Dua 33', 'رَبَّنَاۤ اِنَّكَ لَغَفُوْرٌ شَكُوْرٌ', 'Rabbanaa innaka laghafoorun shakoor.', 'Our Lord is indeed Oft-Forgiving Ready to appreciate (service). (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. The Qur''an mentions how this will be the type of du''a a believer would recite when they enter the Garden of Eden. They will praise Allah and thank him endlessly for being forgiving and appreciative. We are imperfect, we will do wrong and still Allah will forgive us and appreciate our efforts to do the little provision of deeds that we did in our lifetime. Little because we can never do enough to truly be deserving of the rewards in paradise. In this du''a it refer to Allah as Al-Ghafoor and Ash-Shakur two of His rightful names and attributes.', 'Surah Fatir 35:34', 33, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. The Qur''an mentions how this will be the type of du''a a believer would recite when they enter the Garden of Eden. They will praise Allah and thank him endlessly for being forgiving and appreciative. We are imperfect, we will do wrong and still Allah will forgive us and appreciate our efforts to do the little provision of deeds that we did in our lifetime. Little because we can never do enough to truly be deserving of the rewards in paradise. In this du''a it refer to Allah as Al-Ghafoor and Ash-Shakur two of His rightful names and attributes.'),
  ('rabbana_034', 'Rabanna Quranic Dua 34', 'رَبَّنَا وَسِعْتَ كُلَّ شَىْءٍ رَّحْمَةً وَّعِلْمًا فَاغْفِرْ لِلَّذِيْنَ تَابُوْا وَاتَّبَعُوْا سَبِيْلَكَ وَقِهِمْ عَذَابَ الْجَحِيْمِ', 'Rabbanaa wasi''ta kulla shay''ir rahmatanw-wa ''ilmaa; Faghfir lilladheena taaboo wattaba''oo sabeelaka; Waqihim ''adhaabal-jaheem.', 'Our Lord, You have encompassed all things in mercy and knowledge, so forgive those who have repented and followed Your way and protect them from the punishment of Hellfire. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Allah''s knowledge and his mercy know no limit, it is infinite. This du''a asks Allah to be merciful towards all those who believe and have sought istighfar (repentance) from their creator.', 'Surah Ghafir 40:7', 34, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Allah''s knowledge and his mercy know no limit, it is infinite. This du''a asks Allah to be merciful towards all those who believe and have sought istighfar (repentance) from their creator.'),
  ('rabbana_035', 'Rabanna Quranic Dua 35', 'رَبَّنَا وَاَدْخِلْهُمْ جَنّٰتِ عَدْنِ الَّتِىْ وَعَدْتَّهُمْ وَمَنْ صَلَحَ مِنْ اٰبَآئِهِمْ وَاَزْوَاجِهِمْ وَذُرِّيّٰتِهِمْ اِنَّكَ اَنْتَ الْعَزِيْزُ الْحَكِيْمُ، وَقِهِمُ السَّيِّاٰتِ، وَمَنْ تَقِ السَّيِّاٰتِ يَوْمَئِذٍ فَقَدْ رَحِمْتَهٗ، وَذٰلِكَ هُوَ الْفَوْزُ الْعَظِيْمُ', 'Rabbanaa wa adkhilhum jannaati ''adninil-latee wa''adtahum wa man salaha min aabaa''ihim wa azwaajihim wa dhurriyyaatihim; Innaka antal-''azeezul-hakeem; Wa qihimus-sayyi''aat; Wa man taqis-sayyi''aati yawma''idhin faqad rahimtah; Wa dhaalika huwal-fawzul-''azeem.', 'INCOMPLETE — top scrolled. Visible bottom: ...their offspring. Indeed, it is You who is the Exalted in Might, the Wise. And protect them from the evil consequences [of their deeds]. And he whom You protect from evil consequences that Day - You will have given him mercy. And that is the great attainment.', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a asking to unite the believers with their descendants in Jannah (i.e., to be reunited with your forefathers, spouses, and children.) This du''a also calls upon Allah using his rightful attributes of being Al-Aziz (the mighty one) and Al-Hakeem (the wise one). The du''a concludes by asking for protection on the day of judgment and asks to receive his mercy which would be the best of all gifts.', 'Surah Ghafir 40:8-9', 35, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a asking to unite the believers with their descendants in Jannah (i.e., to be reunited with your forefathers, spouses, and children.) This du''a also calls upon Allah using his rightful attributes of being Al-Aziz (the mighty one) and Al-Hakeem (the wise one). The du''a concludes by asking for protection on the day of judgment and asks to receive his mercy which would be the best of all gifts.'),
  ('rabbana_036', 'Rabanna Quranic Dua 36', 'رَبَّنَا اغْفِرْ لَنَا وَلِاِخْوَانِنَا الَّذِيْنَ سَبَقُوْنَا بِالْاِيْمَانِ وَلَا تَجْعَلْ فِىْ قُلُوْبِنَا غِلًّا لِّلَّذِيْنَ اٰمَنُوْا', 'Rabbanaa-ghfir lanaa wa li-ikhwaaninallladheena sabaqoonaa bil-eemaan; Wa laa taj''al fee quloobinaa ghillal-lilladheena aamanoo.', 'Our Lord, forgive us and our brothers who preceded us in faith and put not in our hearts [any] resentment toward those who have believed. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a which reflects the attitude we should have for our fellow Muslim brothers and sisters. Those who ''preceded us in faith'' would refer to those who embraced Islam before the emigration from Makkah to Yathrib. Those who came after would be everyone who accepted Islam after the migration. This du''a is a reminder that we are one Ummah and we should not harbor resentment or hate towards one another. We must continue with love in our hearts for our community and to resist being envious towards any good Allah may have bestowed on another person.', 'Surah Al-Hashr 59:10', 36, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a which reflects the attitude we should have for our fellow Muslim brothers and sisters. Those who ''preceded us in faith'' would refer to those who embraced Islam before the emigration from Makkah to Yathrib. Those who came after would be everyone who accepted Islam after the migration. This du''a is a reminder that we are one Ummah and we should not harbor resentment or hate towards one another. We must continue with love in our hearts for our community and to resist being envious towards any good Allah may have bestowed on another person.'),
  ('rabbana_037', 'Rabanna Quranic Dua 37', 'رَبَّنَاۤ اِنَّكَ رَءُوْفٌ رَّحِيْمٌ', 'Rabbanaa innaka ra''oofur-raheem.', 'Our Lord, indeed You are Kind and Merciful. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a of praise using two of Allah''s rightful names and attributes. The first being Ar-Ra''uf meaning the benign one, the one who is extremely kind and compassionate. The second being Ar-Raheem meaning the most merciful, the one who acts with extreme kindness, bestowing mercy upon his creations.', 'Surah Al-Hashr 59:10', 37, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. A du''a of praise using two of Allah''s rightful names and attributes. The first being Ar-Ra''uf meaning the benign one, the one who is extremely kind and compassionate. The second being Ar-Raheem meaning the most merciful, the one who acts with extreme kindness, bestowing mercy upon his creations.'),
  ('rabbana_038', 'Rabanna Quranic Dua 38', 'رَبَّنَا عَلَيْكَ تَوَكَّلْنَا وَاِلَيْكَ اَنَبْنَا وَاِلَيْكَ الْمَصِيْرُ', 'Rabbanaa ''alayka tawakkalnaa; Wa ilayka anabnaa; Wa ilaykal-maseer.', 'Our Lord, upon You we have relied, and to You we have returned, and to You is the destination. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We must show complete trust and reliance in Allah for all matters. This du''a is one that affirms that we have relied on Him alone. Furthermore, it is also a prayer of remembrance that this life is only temporary. The final destination is when we return to Allah.', 'Surah Al-Mumtahina 60:4', 38, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. We must show complete trust and reliance in Allah for all matters. This du''a is one that affirms that we have relied on Him alone. Furthermore, it is also a prayer of remembrance that this life is only temporary. The final destination is when we return to Allah.'),
  ('rabbana_039', 'Rabanna Quranic Dua 39', 'رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِّلَّذِيْنَ كَفَرُوْا وَاغْفِرْ لَنَا رَبَّنَا اِنَّكَ اَنْتَ الْعَزِيْزُ الْحَكِيْمُ', 'Rabbanaa laa taj''alnaa fitnatan lilladheena kafaroo; Waghfir lanaa rabbanaa; Innaka antal-''adheezul-hakeem.', 'Our Lord, make us not [objects of] torment for the disbelievers and forgive us, our Lord. Indeed, it is You who is the Exalted in Might, the Wise. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim: This is a du''a Prophet Ibrahim recited asking to make the believers victorious over the disbelievers. To not make us ''objects of torment'' meaning if the disbelievers won, they would falsely assume what they followed was correct. They would question how Allah would allow his believers to lose. The du''a then continues referring to Allah as azeezul hakeem meaning the most powerful and wise.', 'Surah Al-Mumtahina 60:5', 39, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Du''a of Prophet Ibrahim: This is a du''a Prophet Ibrahim recited asking to make the believers victorious over the disbelievers. To not make us ''objects of torment'' meaning if the disbelievers won, they would falsely assume what they followed was correct. They would question how Allah would allow his believers to lose. The du''a then continues referring to Allah as azeezul hakeem meaning the most powerful and wise.'),
  ('rabbana_040', 'Rabanna Quranic Dua 40', 'رَبَّنَاۤ اَتْمِمْ لَنَا نُوْرَنَا وَاغْفِرْ لَنَا اِنَّكَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ', 'Rabbanaa atmim lanaa nooranaa waghfir lanaa; Innaka ''alaa kulli shay''in qadeer.', 'Our Lord, perfect for us our light and forgive us. Indeed, You are over all things competent. (Translation: Sahih International)', 1, NULL, 'rabbana_40', 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Another beautiful du''a asking for Jannah. We learn in Surah Al-Hadid verse 12 how on the day of judgment the believing men and women will have a light illuminating from their right hands. They will be told ''a good tiding for you today.'' The hypocrites will find themselves stumbling in darkness. This du''a asks Allah to perfect or to complete our light on that day and to forgive us our sins. Indeed, Allah is competent and powerful over all things.', 'Surah At-Tahrim 66:8', 40, 'Note: There is no specific virtue mentioned in the hadith for reciting the 40 Rabbana Du''as. Another beautiful du''a asking for Jannah. We learn in Surah Al-Hadid verse 12 how on the day of judgment the believing men and women will have a light illuminating from their right hands. They will be told ''a good tiding for you today.'' The hypocrites will find themselves stumbling in darkness. This du''a asks Allah to perfect or to complete our light on that day and to forgive us our sins. Indeed, Allah is competent and powerful over all things.'),
  ('ruquiya_001', 'Protect Your Children From Harm', 'COMPILATION — multiple duas. (1) اُعِيْذُكُمَا بِكَلِمَاتِ اللهِ التَّآمَّةِ، مِنْ كُلِّ شَيْطَانٍ وَّهَامَّةٍ، وَمِنْ كُلِّ عَيْنٍ لَّآمَّةٍ (Sahih al-Bukhari 3371) (2) اُعِيْذُ بِكَلِمَاتِ اللهِ التَّآمَّاتِ مِنْ شَرِّ مَا خَلَقَ (Sunan Abi Dawud 3898) (3) بِسْمِ اللهِ الَّذِىْ لَا يَضُرُّ مَعَ اسْمِهٖ شَىْءٌ فِى الْاَرْضِ وَلَا فِى السَّمَآءِ، وَهُوَ السَّمِيْعُ الْعَلِيْمُ (Al-Adab Al-Mufrad 660) (4) رَبَّنَا هَبْ لَنَا مِنْ اَزْوَاجِنَا وَذُرِّيّٰتِنَا قُرَّةَ اَعْيُنٍ وَّاجْعَلْنَا لِلْمُتَّقِيْنَ اِمَامًا (Al-Furqan 25:74) (5) بِسْمِ اللهِ، بِسْمِ اللهِ، بِسْمِ اللهِ (Sunan Abi Dawud / Hisn al-Muslim 12) (6) بِسْمِ اللهِ تَوَكَّلْتُ عَلَى اللهِ، وَلَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ', 'Compilation — see Arabic field for source attribution per dua', 'O Allah! I seek Refuge with Your Perfect Words from every devil and from poisonous pests and from every evil, harmful, envious eye. — I take refuge in the perfect words of Allah from the evil of what He created. — In the name of Allah with whose name nothing is harmed on earth nor in the heavens and He is The All-Hearing, The All-Knowing. — Our Lord, grant us from among our wives and offspring comfort to our eyes and make us an example for the righteous. — Bismillah, Bismillah, Bismillah. — In the name of Allah, I trust in Allah; there is no might and no power but in Allah.', 1, NULL, 'ruquiya', 'INCOMPLETE-COMPILATION — Ruquiya compilation: Protect your children from harm and negative energy. Multi-dua page combining 6 protective duas with their references.', 'Sahih al-Bukhari 3371 | Sunan Abi Dawud 3898 | Al-Adab Al-Mufrad 660 | Al-Furqan 25:74 | Hisn al-Muslim 12', 1, 'INCOMPLETE-COMPILATION — Ruquiya compilation: Protect your children from harm and negative energy. Multi-dua page combining 6 protective duas with their references.'),
  ('sleep_before_019', 'Surah As-Sajda', 'Recite the entire Surah As-Sajdah (Quran 32 — full Surah, 30 verses). App-level note: link/render via Quran reader rather than inline.', 'Surah As-Sajdah (Quran 32) — full surah recitation', 'Recite Surah As-Sajdah before sleep, paired with Surah Al-Mulk (the following item). The recommended count badge is ''ONCE''.', 1, NULL, 'duas_before_sleep', 'Jabir (RA) said: The Prophet would not sleep until he recited Tanzil as-Sajdah and Tabarak.', 'Surah As-Sajdah (Quran 32) | Jami at-Tirmidhi 3404', 19, 'Jabir (RA) said: The Prophet would not sleep until he recited Tanzil as-Sajdah and Tabarak.'),
  ('sleep_before_020', 'Surah Al-Mulk', 'Recite the entire Surah Al-Mulk (Quran 67 — full Surah, 30 verses). App-level note: link/render via Quran reader rather than inline.', 'Surah Al-Mulk (Quran 67) — full surah recitation', 'Recite Surah Al-Mulk before sleep. Recommended count badge is ''ONCE''.', 1, NULL, 'duas_before_sleep', 'Jabir (RA) said: The Prophet would not sleep until he recited Tanzil as-Sajdah and Tabarak (Tabarak = Surah Al-Mulk).', 'Surah Al-Mulk (Quran 67) | Jami at-Tirmidhi 3404', 20, 'Jabir (RA) said: The Prophet would not sleep until he recited Tanzil as-Sajdah and Tabarak (Tabarak = Surah Al-Mulk).'),
  ('salah_after_005', 'After every Fard Salah', 'لَا اِلٰهَ اِلَّا اللهُ وَحْدَهٗ لَا شَرِيْكَ لَهٗ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، وَهُوَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ، لَا حَوْلَ وَلَا قُوَّةَ اِلَّا بِاللهِ، لَا اِلٰهَ اِلَّا اللهُ، وَلَا نَعْبُدُ اِلَّاۤ اِيَّاهُ، لَهُ النِّعْمَةُ وَلَهُ الْفَضْلُ، وَلَهُ الثَّنَآءُ الْحَسَنُ، لَا اِلٰهَ اِلَّا اللهُ مُخْلِصِيْنَ لَهُ الدِّيْنَ وَلَوْ كَرِهَ الْكَافِرُوْنَ', 'Laa ilaaha illallaah, Wahdahu laa shareeka lah, Lahul mulku wa lahul hamd, Wahuwa ''ala kulli shay''in qadeer, Laa hawla wa laa quwwata illaa billaah, Laa ilaaha illallaah, Wa laa na''budu illaa iiyyaah, Lahun-ni''matu wa lahul-fadlu, Wa lahuth-thanaa''ul hasan, Laa ilaaha illallaah, Mukhliseena lahud-deena wa law karihal-kaafiroon.', 'None has the right to be worshipped except Allah, alone, without partner, to Him belongs all sovereignty and praise and He is over all things omnipotent. There is no might nor power except with Allah, none has the right to be worshipped except Allah and we worship none except Him. For Him is all favor, grace, and glorious praise. None has the right to be worshipped except Allah and we are sincere in faith and devotion to Him although the disbelievers detest it.', 1, NULL, 'duas_after_salah', 'Abu Zubair (RA) reported: Ibn Zubair (RA) uttered at the end of every prayer after pronouncing salutation (these words): There is no god but Allah. He is alone. There is no partner with Him. Sovereignty belongs to Him and He is Potent over everything. There is no might or power except with Allah. There is no god but Allah and we do not worship but Him alone. To Him belong all bounties, to Him belongs all Grace, and to Him is worthy praise accorded. There is no god but Allah, to Whom we are sincere in devotion, even though the unbelievers should disapprove of it. (The narrator said): He (the Holy Prophet) uttered it at the end of every (obligatory) prayer.', 'Sahih Muslim 594a | Sunan an-Nasa''i 1339 | Hisn al-Muslim 68', 5, 'Abu Zubair (RA) reported: Ibn Zubair (RA) uttered at the end of every prayer after pronouncing salutation (these words): There is no god but Allah. He is alone. There is no partner with Him. Sovereignty belongs to Him and He is Potent over everything. There is no might or power except with Allah. There is no god but Allah and we do not worship but Him alone. To Him belong all bounties, to Him belongs all Grace, and to Him is worthy praise accorded. There is no god but Allah, to Whom we are sincere in devotion, even though the unbelievers should disapprove of it. (The narrator said): He (the Holy Prophet) uttered it at the end of every (obligatory) prayer.'),
  ('salah_after_007', 'After Fajr and Maghrib only', 'لَا اِلٰهَ اِلَّا اللهُ وَحْدَهٗ لَا شَرِيْكَ لَهٗ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، يُحْيِىْ وَيُمِيْتُ، وَهُوَ عَلٰى كُلِّ شَىْءٍ قَدِيْرٌ', 'Laa ilaaha illal-laah, Wahdahu laa shareeka lah, Lahul mulku wa lahul hamd, Yuhyee wa yumeet, Wahuwa ''ala kulli shay''in qadeer. (Recite ten times)', 'None has the right to be worshipped except Allah, alone, without partner, to Him belongs all sovereignty and praise, He gives life and causes death and He is over all things omnipotent. (Recite ten times)', 10, NULL, 'duas_after_salah', 'Abu Ayyub Al-Ansari (RA) narrated that the Messenger of Allah said: Whoever says ten times: ''None has the right to be worshipped by Allah, Alone, without partner, to Him belongs all that exists, and to Him belongs the praise, [He gives life and causes death,] and He has power over all things, (La ilaha illallah, wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, [yuhyī wa yumītu,] wa huwa ''ala kulli shai''in qadīr)'' it is for him equal to freeing four slaves among the offspring of Ismaa''il. (Jami at-Tirmidhi 3553). Abu Dharr (RA) narrated that: The Messenger of Allah said: Whoever says at the end of every Fajr prayer, while his feet are still folded, before speaking [the above 10x] — ten good deeds shall be written for him, ten evil deeds shall be wiped away from him, ten degrees shall be raised up for him, and he shall be in security all that day from every disliked thing, and he shall be in protection from Shaitan, and no sin will meet him or destroy him that day, except for associating partners with Allah. (Jami at-Tirmidhi 3474)', 'Jami at-Tirmidhi 3553 | Jami at-Tirmidhi 3474 | Hisn al-Muslim 72', 7, 'Abu Ayyub Al-Ansari (RA) narrated that the Messenger of Allah said: Whoever says ten times: ''None has the right to be worshipped by Allah, Alone, without partner, to Him belongs all that exists, and to Him belongs the praise, [He gives life and causes death,] and He has power over all things, (La ilaha illallah, wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, [yuhyī wa yumītu,] wa huwa ''ala kulli shai''in qadīr)'' it is for him equal to freeing four slaves among the offspring of Ismaa''il. (Jami at-Tirmidhi 3553). Abu Dharr (RA) narrated that: The Messenger of Allah said: Whoever says at the end of every Fajr prayer, while his feet are still folded, before speaking [the above 10x] — ten good deeds shall be written for him, ten evil deeds shall be wiped away from him, ten degrees shall be raised up for him, and he shall be in security all that day from every disliked thing, and he shall be in protection from Shaitan, and no sin will meet him or destroy him that day, except for associating partners with Allah. (Jami at-Tirmidhi 3474)'),
  ('daily_dua_004', 'When Entering Home', 'بِسْمِ اللهِ وَلَجْنَا، وَبِسْمِ اللهِ خَرَجْنَا، وَعَلٰى رَبِّنَا تَوَكَّلْنَا', 'Bismillahi walajnaa, Wa bismillahi kharajnaa, Wa ''ala rabbinaa tawakkalnaa.', 'In the Name of Allah we enter, in the Name of Allah we leave and upon our Lord we depend. Then say: ''As-Salaamu Alaykum'' to those present.', 1, NULL, 'daily_duas', 'Jabir b. Abdullah (RA) reported Allah''s Messenger as saying: When a person enters his house and mentions the name of Allah at the time of entering it and while eating the food, Satan says addressing himself: You have no place to spend the night and no evening meal; but when he enters without mentioning the name of Allah, the Satan says: You have found a place to spend the night, and when he does not mention the name of Allah while eating food, he (the Satan) says: You have found a place to spend the night and evening meal.', 'Sahih Muslim 2018a | Hisn al-Muslim 18', 4, 'Jabir b. Abdullah (RA) reported Allah''s Messenger as saying: When a person enters his house and mentions the name of Allah at the time of entering it and while eating the food, Satan says addressing himself: You have no place to spend the night and no evening meal; but when he enters without mentioning the name of Allah, the Satan says: You have found a place to spend the night, and when he does not mention the name of Allah while eating food, he (the Satan) says: You have found a place to spend the night and evening meal.'),
  ('daily_dua_044', 'Salatul Istikhara', 'اَللّٰهُمَّ اِنِّيْۤ اَسْتَخِيْرُكَ بِعِلْمِكَ، وَاَسْتَقْدِرُكَ بِقُدْرَتِكَ، وَاَسْاَلُكَ مِنْ فَضْلِكَ الْعَظِيْمِ، فَاِنَّكَ تَقْدِرُ وَلَاۤ اَقْدِرُ، وَتَعْلَمُ وَلَاۤ اَعْلَمُ، وَاَنْتَ عَلَّامُ الْغُيُوْبِ. اَللّٰهُمَّ اِنْ كُنْتَ تَعْلَمُ اَنَّ هٰذَا الْاَمْرَ (MENTION THE MATTER BY NAME) خَيْرٌ لِّيْ فِيْ دِيْنِيْ وَمَعَاشِيْ وَعَاقِبَةِ اَمْرِيْ، فَاقْدُرْهُ لِيْ وَيَسِّرْهُ لِيْ ثُمَّ بَارِكْ لِيْ فِيْهِ. وَاِنْ كُنْتَ تَعْلَمُ اَنَّ هٰذَا الْاَمْرَ شَرٌّ لِّيْ فِيْ دِيْنِيْ وَمَعَاشِيْ وَعَاقِبَةِ اَمْرِيْ فَاصْرِفْهُ عَنِّيْ وَاصْرِفْنِيْ عَنْهُ، وَاقْدُرْ لِىَ الْخَيْرَ حَيْثُ كَانَ ثُمَّ ارْضِنِيْ بِهٖ', 'Allahumma innee astakheeruka bi''ilmik; Wa astaqdiruka bi-qudratik; Wa as''aluka min fadlikal-''azeem; Fa innaka taqdiru wa laa aqdir; Wa ta''lamu wa laa a''lam; Wa anta ''allaamul-ghuyoob. Allahumma in kunta ta''lamu anna haadhal-amra (MENTION MATTER BY NAME) khayrun lee fee deenee wa ma''aashee wa ''aaqibati amree, fa''qdurhu lee wa yassirhu lee thumma baarik lee feeh. Wa in kunta ta''lamu anna haadhal-amra sharrun lee fee deenee wa ma''aashee wa ''aaqibati amree, fasrifhu ''annee wasrifnee ''anhu, waqdur lee al-khayra haythu kaan, thumma raddinee bih.', 'O Allah, I seek Your guidance (in making a choice) by virtue of Your knowledge, and I seek ability by virtue of Your power, and I ask You of Your great bounty. You have power, I have none. And You know, I do not know, and You are the Knower of hidden things. O Allah, if in Your knowledge this matter (then it should be mentioned by name) is good for me both in this world and in the Hereafter (or in my religion, my livelihood and my affairs), then ordain it for me, make it easy for me, and bless it for me. And if in Your knowledge it is bad for me and for my religion, my livelihood and my affairs (or in this world and the next) then turn it away from me and turn me away from it, and ordain for me the good wherever it may be and make me pleased with it.', 1, NULL, 'daily_duas', 'Narrated Jabir bin Abdullah (RA): The Prophet used to teach us the way of doing Istikhara (means to ask Allah to guide one to the right sort of action concerning any job or a deed), in all matters as he taught us the Suras of the Qur''an. He said: If anyone of you thinks of doing any job he should offer a two rak''at prayer other than the compulsory ones and say (after the prayer) [the above dua]. The Prophet added that then the person should name (mention his need).', 'Sahih al-Bukhari 1166', 44, 'Narrated Jabir bin Abdullah (RA): The Prophet used to teach us the way of doing Istikhara (means to ask Allah to guide one to the right sort of action concerning any job or a deed), in all matters as he taught us the Suras of the Qur''an. He said: If anyone of you thinks of doing any job he should offer a two rak''at prayer other than the compulsory ones and say (after the prayer) [the above dua]. The Prophet added that then the person should name (mention his need).'),
  ('ruquiya_002', 'Healing and protection from sickness', 'COMPILATION — full Quranic ruqyah recitation page. Includes (in order): Isti''adhah; Surah Al-Fatihah (1:1-7); Al-Baqarah 1-5; Al-Baqarah 254 (Ayat al-Kursi prelude); Ayat al-Kursi (Al-Baqarah 255); Al-Baqarah 256 (Laa ikraaha fid-deen); Al-Baqarah 285-286 (last two ayat of Surah Al-Baqarah); Al-Imran 18 (Shahidallaahu...); Surah Al-Hashr 22-24; multiple supplications including A''oodhu bi-kalimaatillaahit-taammah min sharri ma khalaq; Allahumma rabban-naas, adh''hib il-ba''sa; A''oodhu bi-kalimatillaah at-taammaati min kulli shaytanin wa hammah, wa min kulli ''aynin laammah; As''alullaaha al-''adheem rabbal ''arshil-''adheem an yashfiyak; Salawat Ibrahim; final ayahs from Surah Al-Kafiroon (109) + Al-Ikhlas (112) + Al-Falaq (113) + An-Naas (114).', 'COMPILATION — recite the Quranic ruqyah Surahs and protective verses for healing', 'Quranic ruqyah compilation for healing and protection from sickness. Recommended app-level approach: render this as a sequential reading of the constituent Surahs/ayahs via the Quran reader, with the supplications shown inline between Surah blocks.', 1, NULL, 'ruquiya', 'Standard ruqyah compilation referenced across multiple hadith collections. Key benefit hadith: Aisha (RA) narrated that when the Prophet would go to bed every night, he would cup his hands together and blow over them after reciting Surah Al-Ikhlas, Al-Falaq, and An-Naas, then rub his hands over whatever parts of his body he was able to reach. (Sahih al-Bukhari 5017). For sickness, the Prophet would also recite over the ill: Adh''hibil ba''sa rabban naas, washfi antash shafee...', 'Surah Al-Fatihah | Al-Baqarah 1-5, 254-256, 285-286 | Al-Imran 18 | Al-Hashr 22-24 | Surah Al-Kafiroon (109) | Al-Ikhlas (112) | Al-Falaq (113) | An-Naas (114) | Sahih al-Bukhari 5017', 2, 'Standard ruqyah compilation referenced across multiple hadith collections. Key benefit hadith: Aisha (RA) narrated that when the Prophet would go to bed every night, he would cup his hands together and blow over them after reciting Surah Al-Ikhlas, Al-Falaq, and An-Naas, then rub his hands over whatever parts of his body he was able to reach. (Sahih al-Bukhari 5017). For sickness, the Prophet would also recite over the ill: Adh''hibil ba''sa rabban naas, washfi antash shafee...'),
  ('ruquiya_003', 'Guard against black magic and evil influences', 'COMPILATION — full Quranic ruqyah recitation page. Includes (in order): Isti''adhah; Surah Al-Fatihah (1:1-7); Al-Baqarah 1-5 (opening); Al-Baqarah 102 (about Harut and Marut); Al-Baqarah 163-164 (Wa ilaahukum Ilaahuw-Waahid); Ayat al-Kursi (2:255-257); plus closing Surahs typically used as ruqyah against sihr.', 'COMPILATION — recite for guarding against black magic and evil influences', 'Quranic ruqyah compilation specifically targeted at sihr (black magic) and evil influences. The selected verses include those that mention magic explicitly (Al-Baqarah 102) and the most powerful tawheed verses (Ayat al-Kursi, Al-Imran 18) as a counter to shirk-laden practices.', 1, NULL, 'ruquiya', 'Standard ruqyah compilation against sihr (black magic). The Prophet himself was treated with the three Quls (Al-Ikhlas, Al-Falaq, An-Naas) when affected by magic — Sahih al-Bukhari 5763.', 'Surah Al-Fatihah | Al-Baqarah 1-5, 102, 163-164, 255-257 | Al-Ikhlas (112) | Al-Falaq (113) | An-Naas (114) | Sahih al-Bukhari 5763', 3, 'Standard ruqyah compilation against sihr (black magic). The Prophet himself was treated with the three Quls (Al-Ikhlas, Al-Falaq, An-Naas) when affected by magic — Sahih al-Bukhari 5763.'),
  ('ruquiya_004', 'Shield yourself from all evil forces', 'COMPILATION — full Quranic ruqyah recitation page. Includes (in order): Isti''adhah; Surah Al-Fatihah; Al-Baqarah 1-5; Al-Baqarah 21-22 (Ya ayyuhan-naas u''budoo Rabbakumul-ladhee khalaqakum); Al-Baqarah 102 (Harut and Marut / magic); Al-Baqarah 163 (tawheed); Ayat al-Kursi (2:255); additional protective ayahs from various Surahs.', 'COMPILATION — recite as a comprehensive shield against all evil forces', 'General-purpose Quranic ruqyah compilation covering protection from all evil — magic, jinn, evil eye, and shaytan. Broader in scope than #3 (which is specifically anti-magic).', 1, NULL, 'ruquiya', 'Comprehensive ruqyah compilation. Aisha narrated that the Prophet, when any one of his family fell sick, would recite over him by blowing. (Sahih Muslim 2192). Uthman bin Abi al-As reported a complaint of pain to the Messenger of Allah; he said: Place your hand on the part of your body where you feel pain and say ''Bismillah'' three times and seven times ''A''oodhu billaahi wa qudratihi min sharri ma ajidu wa uhaadhir.'' (Sahih Muslim 2202)', 'Surah Al-Fatihah | Al-Baqarah 1-5, 21-22, 102, 163, 255 | Sahih Muslim 2192 | Sahih Muslim 2202', 4, 'Comprehensive ruqyah compilation. Aisha narrated that the Prophet, when any one of his family fell sick, would recite over him by blowing. (Sahih Muslim 2192). Uthman bin Abi al-As reported a complaint of pain to the Messenger of Allah; he said: Place your hand on the part of your body where you feel pain and say ''Bismillah'' three times and seven times ''A''oodhu billaahi wa qudratihi min sharri ma ajidu wa uhaadhir.'' (Sahih Muslim 2202)')
;

