-- 6. Verify --------------------------------------------------------------
SELECT category_id, COUNT(*) AS item_count
FROM azkar_items
WHERE category_id IN ('duas_before_sleep', 'duas_after_salah', 'ruquiya', 'rabbana_40', 'remembrance_of_allah', 'daily_duas')
GROUP BY category_id
ORDER BY category_id;

-- Sanity: morning/evening counts must be unchanged from before this migration.
SELECT category_id, COUNT(*) AS item_count
FROM azkar_items
WHERE category_id IN ('morning', 'evening')
GROUP BY category_id
ORDER BY category_id;

